window.CADRO_PAGE_HTML=window.CADRO_PAGE_HTML||{};window.CADRO_PAGE_HTML["tr"]={"ats-ise-alim-yazilimi":`<section class="hero reveal-on-scroll is-visible" style="padding-top: 60px;">\n  <div class="hero-copy">\n    <p class="eyebrow">ADAY TAKİP SİSTEMİ (ATS)</p>\n    <h1>Aday Takip Sistemi (ATS) ve İşe Alım Yazılımı</h1>\n    <p class="hero-text">ATS (Aday Takip Sistemi) ile başvuruları tek ekranda toplayın, mülakat aşamalarını netleştirin ve işe alım operasyonunu ekipler arasında izlenebilir hale getirin. CADRO ATS ile işe alım döngüsü hızlanır, aday görünürlüğü artar ve İK ekipleri manuel iş yükünü azaltır.</p>\n     <div class="hero-actions">\n       <a class="primary-button" href="#nasil-calisir">ATS Akışını Gör</a>\n       <a class="ghost-button" href="#ozellikler">Nasıl Çalışır?</a>\n    </div>\n  </div>\n  <div class="hero-panel">\n    <figure class="hero-screenshot">\n      <img src="./assets/screenshots/phase3/tr/ats.webp" alt="CADRO aday takip sistemi ATS pano görünümü" class="product-shot" loading="eager" fetchpriority="high" style="border-radius: 12px; box-shadow: 0 20px 40px rgba(0,0,0,0.1);" />\n    </figure>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll" id="nasil-calisir">\n  <div class="section-head narrow">\n    <p class="eyebrow">NASIL ÇALIŞIR?</p>\n    <h2>Başvurudan teklif mektubuna 4 adımda</h2>\n  </div>\n  <div class="steps-grid">\n    <div class="step-card">\n      <span class="step-num">1</span>\n      <h3>Pozisyon Oluştur &amp; Yayınla</h3>\n      <p>Pozisyonu departman ve başlıkla tanımla. Kariyer sayfana tek tıkla ekle, aktif/pasif olarak yönet.</p>\n    </div>\n    <div class="step-card">\n      <span class="step-num">2</span>\n      <h3>AI CV Filtreleme</h3>\n      <p>CV yüklendiğinde yapay zeka devreye girer: iletişim, teknik yetkinlik, kültürel uyum ve motivasyon 4 kriterde puanlanır, özet otomatik üretilir.</p>\n    </div>\n    <div class="step-card">\n      <span class="step-num">3</span>\n      <h3>Kanban'da Aşama Aşama</h3>\n      <p>Mülakat → Test → Referans → Teklif: adayları sürükle-bırak ile taşı, ekip notları ve HR Scorecard ile zenginleştir.</p>\n    </div>\n    <div class="step-card">\n      <span class="step-num">4</span>\n      <h3>Teklif Mektubu &amp; Personel Kartı</h3>\n      <p>Kişiselleştirilmiş PDF teklif mektubunu gönder. Tek tıkla personel kartına dönüştür; özlük ve bordro başlar.</p>\n    </div>\n  </div>\n</section>\n\n<section class="strip reveal-on-scroll" style="margin-top: 40px;">\n  <div>\n    <span class="strip-label">Problem</span>\n    <p>Başvuruların farklı kanallarda dağılması, mülakat notlarının kaybolması ve time-to-hire süresinin uzaması.</p>\n  </div>\n  <div>\n    <span class="strip-label">CADRO Çözümü</span>\n    <p>Tüm adayları tek havuzda toplayan, sürükle-bırak akış ve değerlendirme akışı sunan merkezi ATS yapısı.</p>\n  </div>\n  <div>\n    <span class="strip-label">Sonuç</span>\n    <p>Daha görünür işe alım süreci, daha hızlı karar alma ve aday deneyiminde daha güçlü kurumsal standart.</p>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll" id="ozellikler">\n  <div class="section-head narrow">\n    <p class="eyebrow">ATS MODÜLÜ</p>\n    <h2>Yapay zeka destekli, başvurudan teklif mektubuna tam döngü</h2>\n  </div>\n  <div class="card-grid" style="grid-template-columns: repeat(3, minmax(0, 1fr));">\n    <article class="feature-card">\n      <h3>Kanban Aday Tahtası</h3>\n      <p>Adayları Yeni Başvuru'dan Teklif'e sürükle-bırak ile taşıyın. Kimin hangi aşamada olduğu tüm ekibe anlık görünür.</p>\n    </article>\n    <article class="feature-card">\n      <h3>AI Destekli CV Puanlama</h3>\n      <p>CV yüklendiği anda yapay zeka devreye girer: iletişim, teknik yetkinlik, kültürel uyum ve motivasyon 4 kriterde otomatik puanlanır, genel özet üretilir.</p>\n    </article>\n    <article class="feature-card">\n      <h3>4 Boyutlu HR Scorecard</h3>\n      <p>Mülakatçılar her aday için artıları, eksileri ve genel değerlendirmeyi kayıt altına alır. Puanlama iletişim, teknik, kültür ve motivasyon olmak üzere 4 boyutta yapılır.</p>\n    </article>\n    <article class="feature-card">\n      <h3>Dinamik Teklif Mektubu</h3>\n      <p>İş teklifini sistem içinden kişiselleştirilmiş PDF olarak üretin. Şablon ilanın detaylarıyla otomatik dolar, tek tıkla adaya iletin.</p>\n    </article>\n    <article class="feature-card">\n      <h3>Süreç Rozetleri & Akış Notları</h3>\n      <p>"CV İncelendi", "Telefon Görüşmesi" ve "Mülakat Tamamlandı" gibi rozetlerle süreci şeffaf tutun. Ekip notları aynı kart üzerinde birikir.</p>\n    </article>\n    <article class="feature-card">\n      <h3>Merkezi İlan ve Havuz Yönetimi</h3>\n      <p>Departman bazlı iş ilanı oluşturun, aktif/pasif olarak yönetin. Tüm kanallardan gelen başvurular tek havuzda toplanır.</p>\n    </article>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll">\n  <div class="showcase-stack">\n    <article class="showcase-row">\n      <div class="showcase-copy">\n        <p class="eyebrow">OPERASYONEL NETLİK</p>\n        <h3>Her aday için daha temiz ve izlenebilir akış</h3>\n        <p>Yeni aday ekleme, stage yönetimi ve ekip içi karar süreçleri aynı yapı içinde ilerler. Böylece işe alım sadece hızlı değil, aynı zamanda daha kontrollü hale gelir.</p>\n        <a href="dijital-ozluk-ve-izin.html" style="color: var(--cyan); font-weight: 800; display: inline-block; margin-top: 10px;">Dijital Özlük Modülüne Göz At →</a>\n      </div>\n      <div class="showcase-media">\n        <img src="./assets/screenshots/phase3/tr/ats-modal.webp" alt="CADRO ATS yeni aday ekleme ekranı" class="product-shot" loading="lazy" />\n      </div>\n    </article>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll">\n  <div class="section-head narrow">\n    <p class="eyebrow">İÇ LİNK YAPISI</p>\n    <h2>ATS, diğer İK operasyonlarıyla birlikte daha güçlü çalışır</h2>\n  </div>\n  <div class="card-grid" style="grid-template-columns: repeat(3, minmax(0, 1fr));">\n    <article class="feature-card">\n      <h3>Dijital Özlük ve İzin Yönetimi</h3>\n      <p>İşe alınan çalışanları belge ve izin süreçlerine daha hızlı taşıyın.</p>\n      <a href="dijital-ozluk-ve-izin.html" style="color: var(--cyan); font-weight: 800;">Özlük ve İzin Modülünü İncele →</a>\n    </article>\n    <article class="feature-card">\n      <h3>Performans ve OKR</h3>\n      <p>Yeni işe alınan çalışanları hedef ve gelişim yapısına daha kolay entegre edin.</p>\n      <a href="performans-degerlendirme-okr.html" style="color: var(--cyan); font-weight: 800;">Performans Modülünü İncele →</a>\n    </article>\n    <article class="feature-card">\n      <h3>Puantaj ve Vardiya Yönetimi</h3>\n      <p>Operasyonel işe girişten sonra devam, vardiya ve zaman yönetimini tek ekrana bağlayın.</p>\n      <a href="puantaj-ve-vardiya-yazilimi.html" style="color: var(--cyan); font-weight: 800;">Puantaj Modülünü İncele →</a>\n    </article>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll" style="background: #f8fafc; padding: 60px 20px;">\n  <div class="section-head narrow">\n    <p class="eyebrow">MERAK EDİLENLER</p>\n    <h2>Sıkça Sorulan Sorular</h2>\n  </div>\n  <div class="seo-faq">\n    <details>\n      <summary>Aday Takip Sistemi (ATS) nedir ve ne işe yarar?</summary>\n      <p>ATS, işe alım sürecini dijitalleştiren ve başvuruları tek bir yapı içinde yöneten yazılımdır. Aday akışını görünür hale getirir ve işe alım ekiplerinin operasyonel yükünü azaltır.</p>\n    </details>\n    <details>\n      <summary>CADRO ATS ile mülakat süreci nasıl daha düzenli ilerler?</summary>\n      <p>Adaylar belirli aşamalarda takip edilir, ekip notları tek merkezde tutulur ve kimin hangi aşamada olduğu net şekilde görülebilir.</p>\n    </details>\n    <details>\n      <summary>CADRO ATS diğer İK modülleriyle birlikte çalışır mı?</summary>\n      <p>Evet. İşe alım sonrası çalışan verileri, özlük ve diğer insan kaynakları süreçlerine daha düzenli biçimde aktarılabilecek şekilde konumlanır.</p>\n    </details>\n    <details>\n      <summary>ATS hangi şirketler için uygundur?</summary>\n      <p>Birden fazla pozisyon için başvuru toplayan, mülakat akışını görünür hale getirmek isteyen ve ekipler arası işe alım koordinasyonunu güçlendirmeyi hedefleyen şirketler için uygundur.</p>\n    </details>\n    <details>\n      <summary>ATS ile işe giriş bağlantısı nasıl kurulur?</summary>\n      <p>İşe alım süreci tamamlandığında, aday bilgileri ilgili insan kaynakları akışlarına daha kontrollü biçimde taşınabilir ve işe giriş hazırlıkları aynı yapı içinde ilerleyebilir.</p>\n    </details>\n  </div>\n</section>\n\n<section class="section final-cta reveal-on-scroll">\n  <div class="contact-card">\n    <div>\n      <p class="eyebrow">HAZIR MISINIZ?</p>\n      <h2>İşe alım akışınızı bugün daha görünür hale getirin.</h2>\n      <p>CADRO ile başvuru, değerlendirme ve karar süreçlerini tek platformda yönetin.</p>\n    </div>\n    <div class="contact-actions">\n      <a class="primary-button" href="pricing.html" data-i18n-key="btn_view_plans"></a>\n      <a class="ghost-button" href="mailto:info@cadro.io">Satış Ekibine Ulaş</a>\n    </div>\n  </div>\n</section>\n    `,blog:`<section class="hero reveal-on-scroll is-visible" style="padding-top: 80px; padding-bottom: 60px; display: flex; flex-direction: column; align-items: center; justify-content: center; text-align: center;">\n          <div class="hero-copy" style="max-width: 900px; margin: 0 auto; display: flex; flex-direction: column; align-items: center; text-align: center;">\n            <h1 style="font-size: clamp(3rem, 6vw, 5rem); font-weight: 800; color: #0f172a; line-height: 1.1; margin-bottom: 15px; letter-spacing: -1px;">CADRO AKADEMİ</h1>\n            <h2 style="font-size: clamp(1.5rem, 3vw, 2.2rem); font-weight: 700; color: var(--cyan); margin-bottom: 25px;">İK'nın Geleceğini Bugünden Keşfedin</h2>\n            <p class="hero-text" style="font-size: 1.2rem; max-width: 700px; color: #475569;">Yapay zeka devrimi, veri odaklı karar alma ve kurumsal kültür inşası üzerine C-Level yöneticiler için hazırladığımız stratejik içerikler.</p>\n          </div>\n        </section>\n\n        <section class="section reveal-on-scroll" style="background: #f8fafc; padding: 60px 20px;">\n          <div class="blog-grid">\n            \n            <article class="blog-card" style="border-left: 4px solid var(--cyan);">\n              <div class="blog-meta">05 Nisan 2026 • İK ve Yapay Zeka</div>\n              <h3>Üretken Yapay Zeka (GenAI) ile İK Operasyonlarında Haftalık 15 Saat Tasarruf</h3>\n              <p>İş ilanları yazmak, mülakat soruları hazırlamak ve performans metinlerini derlemek... Yapay zekayı bir İK asistanı olarak kullanarak operasyonel yükü nasıl sıfırlarsınız?</p>\n              <a href="makale-yapay-zeka-genai.html" class="read-more">Makaleyi Oku →</a>\n            </article>\n\n            <article class="blog-card" style="border-left: 4px solid var(--cyan);">\n              <div class="blog-meta">02 Nisan 2026 • İK ve Yapay Zeka</div>\n              <h3>Kimin İstifa Edeceğini Önceden Bilen Algoritmalar: Prediktif İK</h3>\n              <p>Tahmine dayalı analitik (Predictive Analytics) kullanarak hangi kilit çalışanınızın ayrılma riski taşıdığını aylar öncesinden tespit edebilir ve önlem alabilirsiniz.</p>\n              <a href="makale-prediktif-ik.html" class="read-more">Makaleyi Oku →</a>\n            </article>\n\n            <article class="blog-card" style="border-left: 4px solid var(--cyan);">\n              <div class="blog-meta">28 Mart 2026 • İK ve Yapay Zeka</div>\n              <h3>İşe Alımda Yapay Zeka: Önyargıları (Bias) Yok Etmek mi, Derinleştirmek mi?</h3>\n              <p>CV tarama süreçlerinde yapay zeka kullanımının avantajları ve CHRO'ların dikkat etmesi gereken etik algoritmik filtreleme standartları.</p>\n              <a href="makale-ise-alimda-ai-etik.html" class="read-more">Makaleyi Oku →</a>\n            </article>\n\n            <article class="blog-card" style="border-left: 4px solid var(--cyan);">\n              <div class="blog-meta">25 Mart 2026 • İK ve Yapay Zeka</div>\n              <h3>AI vs KVKK İkilemi: Çalışan Verilerini İşlerken Hukuki Riskleri Yönetmek</h3>\n              <p>Yapay zeka algoritmalarını çalışan verilerinizle beslerken Veri Koruma Kanunu'na nasıl tam uyumlu kalırsınız? Hukuk departmanınızın bilmesi gerekenler.</p>\n              <a href="makale-ai-ve-kvkk-uyumu.html" class="read-more">Makaleyi Oku →</a>\n            </article>\n\n            <article class="blog-card">\n              <div class="blog-meta">18 Mart 2026 • Şirket Kültürü</div>\n              <h3>Sessiz İstifa (Quiet Quitting) Şirketinize Ne Kadar Mal Oluyor?</h3>\n              <p>Çalışanlarınız fiziken ofiste ama ruhen ayrılmış olabilir mi? Düşük bağlılığın gizli OPEX maliyetlerini hesaplıyor ve çözüm üretiyoruz.</p>\n              <a href="makale-sessiz-istifa-maliyeti.html" class="read-more">Makaleyi Oku →</a>\n            </article>\n\n            <article class="blog-card">\n              <div class="blog-meta">10 Mart 2026 • İK Otomasyonu</div>\n              <h3>2026 İnsan Kaynakları Dijital Dönüşüm Rehberi</h3>\n              <p>Excel tabloları artık bir yönetim aracı değil, bir güvenlik riskidir. CFO'ların İK yatırımlarından (ROI) beklentileri ve dijitalleşmenin kuralları.</p>\n              <a href="makale-ik-dijital-donusum-2026.html" class="read-more">Makaleyi Oku →</a>\n            </article>\n\n            <article class="blog-card">\n              <div class="blog-meta">28 Şubat 2026 • Yetenek Yönetimi</div>\n              <h3>Yüksek Turnover Oranını Düşürmenin 5 Veri Odaklı Yolu</h3>\n              <p>Parlak yetenekler neden ilk 3 ayda istifa ediyor? Kötü işe giriş deneyiminin hukuki ve finansal zararları üzerine çarpıcı araştırma verileri.</p>\n              <a href="makale-turnover-dusurme-yollari.html" class="read-more">Makaleyi Oku →</a>\n            </article>\n\n            <article class="blog-card">\n              <div class="blog-meta">10 Şubat 2026 • Performans</div>\n              <h3>Yıllık Performans Görüşmelerinin Sonu Geldi mi?</h3>\n              <p>Çalışanların %70'i yılda bir kez yapılan performans görüşmelerinin adil olmadığına inanıyor. 360 derece anlık geri bildirim kültürüne geçişin avantajları.</p>\n              <a href="makale-yillik-performans-degerlendirme.html" class="read-more">Makaleyi Oku →</a>\n            </article>\n\n            <article class="blog-card">\n              <div class="blog-meta">22 Ocak 2026 • Yasal Uyum</div>\n              <h3>Dijital Özlük Dosyası ve KVKK Denetimleri</h3>\n              <p>İş müfettişleri kapınızı çaldığında klasörler arasında boğulmamak için bilmeniz gerekenler. Elektronik arşivlemenin hukuki geçerliliği.</p>\n              <a href="makale-dijital-ozluk-ve-kvkk.html" class="read-more">Makaleyi Oku →</a>\n            </article>\n\n            <article class="blog-card">\n              <div class="blog-meta">05 Ocak 2026 • Bordro & Finans</div>\n              <h3>Bordro Sızıntıları: Excel ile Puantaj Yapmanın Acı Bedeli</h3>\n              <p>Hatalı fazla mesai hesaplamaları ve gece vardiyası çarpanlarındaki sapmalar, toplam bordro bütçenizi her ay nasıl eritiyor?</p>\n              <a href="makale-excel-bordro-sizintilari.html" class="read-more">Makaleyi Oku →</a>\n            </article>\n\n            <article class="blog-card" style="border-left: 4px solid var(--cyan);">\n              <div class="blog-meta">05 Mayıs 2026 • İş Hukuku &amp; İK Yönetimi</div>\n              <h3>Esnek Çalışma Saatleri 2026: İK'nın Yasal Rehberi</h3>\n              <p>Denkleştirme süresi, uzaktan çalışma mevzuatı, SGK bildirimi ve İK yazılımı entegrasyonu: 2026 İş Kanunu güncellemeleriyle kapsamlı rehber.</p>\n              <a href="makale-esnek-calisma-saatleri-2026.html" class="read-more">Makaleyi Oku →</a>\n            </article>\n\n            <article class="blog-card" style="border-left: 4px solid var(--cyan);">\n              <div class="blog-meta">12 Mayıs 2026 • Onboarding &amp; İşe Alım</div>\n              <h3>Onboarding Süreci Nasıl Dijitalleştirilir? 2026 Rehberi</h3>\n              <p>Dijital sözleşme, e-oryantasyon, görev otomasyonu ve KVKK uyumlu personel dosyası ile onboarding maliyetini %60 düşürün.</p>\n              <a href="makale-onboarding-dijitallestirme.html" class="read-more">Makaleyi Oku →</a>\n            </article>\n\n          </div>\n        </section>\n    `,"dijital-ozluk-ve-izin":`<section class="hero reveal-on-scroll is-visible" style="padding-top: 60px;">\n  <div class="hero-copy">\n    <p class="eyebrow">DİJİTAL ÖZLÜK DOSYASI VE İZİN YÖNETİMİ</p>\n    <h1>Çalışan belgelerini ve <br><span>izin süreçlerini tek merkezde yönetin.</span></h1>\n    <p class="hero-text">Dijital özlük dosyası ile çalışan belgelerini, belge yükleme, eksik evrak takibi ve izin onay akışlarını tek platformda yönetin. CADRO ile İK operasyonları daha görünür, daha kontrollü ve daha ölçülebilir hale gelir.</p>\n     <div class="hero-actions">\n       <a class="primary-button" href="pay.html?plan=start&billing=monthly">Basic Planı İncele</a>\n       <a class="ghost-button" href="#ozellikler">Nasıl Çalışır?</a>\n    </div>\n  </div>\n  <div class="hero-panel">\n    <figure class="hero-screenshot">\n      <img src="./assets/screenshots/phase3/tr/e-dossier.webp" alt="CADRO dijital özlük dosyası ve izin yönetimi ekranı" class="product-shot" loading="eager" fetchpriority="high" style="border-radius: 12px; box-shadow: 0 20px 40px rgba(0,0,0,0.1);" />\n    </figure>\n  </div>\n</section>\n\n<section class="strip reveal-on-scroll" style="margin-top: 40px;">\n  <div>\n    <span class="strip-label">Problem</span>\n    <p>Belge takibinin dağınık ilerlemesi, eksik evrak riskleri ve izin taleplerinin manuel şekilde yönetilmesi.</p>\n  </div>\n  <div>\n    <span class="strip-label">CADRO Çözümü</span>\n    <p>Dijital özlük dosyası, belge yükleme, uyum görünümü ve izin onay akışını tek merkezde birleştiren yapı.</p>\n  </div>\n  <div>\n    <span class="strip-label">Sonuç</span>\n    <p>Daha güçlü belge görünürlüğü, daha düzenli İK operasyonu ve çalışan deneyiminde daha yalın süreçler.</p>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll" id="ozellikler">\n  <div class="section-head narrow">\n    <p class="eyebrow">OZLUK & İZİN MODÜLÜ</p>\n    <h2>Belge arşivinden izin onayına, kıdemden uyum kaydına tam döngü</h2>\n  </div>\n  <div class="card-grid" style="grid-template-columns: repeat(3, minmax(0, 1fr));">\n    <article class="feature-card">\n      <h3>Kategorili Belge Arşivi</h3>\n      <p>Her belge kategori ve türüyle (kimlik, sözleşme, sağlık raporu vb.) kaydedilir. Zorunlu belgeler <code>is_mandatory</code> alanıyla işaretlenir; APPROVED / PENDING / REJECTED durumu anlık görünür.</p>\n    </article>\n    <article class="feature-card">\n      <h3>Geçerlilik & Eksik Evrak Alarmları</h3>\n      <p>Her belgenin <code>expiry_date</code> alanı izlenir; süresi dolmak üzere olan belgeler otomatik uyarı tetikler. Zorunlu evrakı eksik personel için compliance listesi anında oluşturulur.</p>\n    </article>\n    <article class="feature-card">\n      <h3>İzin Talebi & Rol Bazlı Onay</h3>\n      <p>Çalışan talep oluşturur → departman müdürü → HR / ADMIN onayı sırayla tetiklenir. Her adım kayıt altında; talep PENDING / APPROVED / REJECTED / CANCELLED olarak kapanır.</p>\n    </article>\n    <article class="feature-card">\n      <h3>Kıdem Bazlı İzin Hesabı</h3>\n      <p>Kıdem yılına göre otomatik hak belirlenir (0–1, 1–5, 5–15, 15+ yıl). Devir hakkı politikaya bağlı <code>max_carry_over_days</code> sınırıyla kontrol edilir; kullanılan / bekleyen / kalan ayrımı anlık görünür.</p>\n    </article>\n    <article class="feature-card">\n      <h3>Çoklu İzin Türleri</h3>\n      <p>Yıllık (ANNUAL), sağlık (SICK), mazeret (EXCUSED) ve doğum (MATERNITY) izinleri ayrı bakiyelerde izlenir. Her türün talebi bağımsız onay akışına yönlenir.</p>\n    </article>\n    <article class="feature-card">\n      <h3>Denetim & Uyum Kaydı</h3>\n      <p>Her belge işleminde DocumentActionLog kayıt oluşturur: kim ne yaptı, önceki / yeni durum, zaman damgası. KVKK ve iş müfettişi denetimine hazır.</p>\n    </article>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll">\n  <div class="showcase-stack">\n    <article class="showcase-row">\n      <div class="showcase-copy">\n        <p class="eyebrow">BELGE YÜKLEME</p>\n        <h3>Çalışan belgelerini düzenli bir akışta arşivleyin</h3>\n        <p>Belge kategorisi, geçerlilik tarihi ve zorunlu evrak mantığı ile çalışan dosyalarını dağınık klasörlerden kurtarın.</p>\n      </div>\n      <div class="showcase-media">\n        <img src="./assets/screenshots/phase3/tr/e-dossier-upload.webp" alt="CADRO özlük dosyasına belge yükleme ekranı" class="product-shot" loading="lazy" />\n      </div>\n    </article>\n    <article class="showcase-row">\n      <div class="showcase-copy">\n        <p class="eyebrow">COMPLIANCE GÖRÜNÜMÜ</p>\n        <h3>Eksik evrak ve uyum risklerini daha görünür hale getirin</h3>\n        <p>Belge tamamlama skoru, eksik evrak listesi ve uyum özeti sayesinde İK ekipleri daha proaktif hareket edebilir.</p>\n      </div>\n      <div class="showcase-media">\n        <img src="./assets/screenshots/phase3/tr/e-dossier-compliance.webp" alt="CADRO özlük dosyası uyum ve compliance özeti ekranı" class="product-shot" loading="lazy" />\n      </div>\n    </article>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll">\n  <div class="section-head narrow">\n    <p class="eyebrow">İÇ LİNK YAPISI</p>\n    <h2>Özlük süreçleri, diğer modüllerle birlikte daha verimli çalışır</h2>\n  </div>\n  <div class="card-grid" style="grid-template-columns: repeat(3, minmax(0, 1fr));">\n    <article class="feature-card">\n      <h3>Puantaj ve Vardiya Yönetimi</h3>\n      <p>İzin, devamsızlık ve günlük operasyon akışını zaman yönetimiyle daha bütüncül ele alın.</p>\n      <a href="puantaj-ve-vardiya-yazilimi.html" style="color: var(--cyan); font-weight: 800;">Puantaj Modülünü İncele →</a>\n    </article>\n    <article class="feature-card">\n      <h3>Performans ve OKR</h3>\n      <p>Çalışan verisi, gelişim görünümü ve performans takibini tek İK yapısı altında bütünleştirin.</p>\n      <a href="performans-degerlendirme-okr.html" style="color: var(--cyan); font-weight: 800;">Performans Modülünü İncele →</a>\n    </article>\n    <article class="feature-card">\n      <h3>Güvenlik ve Uyum</h3>\n      <p>Belge güvenliği, veri yönetimi ve sistem yaklaşımını daha detaylı inceleyin.</p>\n      <a href="security.html" style="color: var(--cyan); font-weight: 800;">Güvenlik Sayfasını İncele →</a>\n    </article>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll" style="background: #f8fafc; padding: 60px 20px;">\n  <div class="section-head narrow">\n    <p class="eyebrow">MERAK EDİLENLER</p>\n    <h2>Sıkça Sorulan Sorular</h2>\n  </div>\n  <div class="seo-faq">\n    <details>\n      <summary>Dijital özlük dosyası ne işe yarar?</summary>\n      <p>Çalışan belgelerini tek merkezde yönetmeye, eksik evrak risklerini azaltmaya ve İK operasyonlarını daha hızlı yürütmeye yardımcı olur.</p>\n    </details>\n    <details>\n      <summary>İzin yönetimi ile özlük dosyası aynı platformda kullanılabilir mi?</summary>\n      <p>Evet. CADRO, çalışan belge yönetimi ve izin akışını aynı yapı içinde sunarak operasyonel bütünlük sağlar.</p>\n    </details>\n    <details>\n      <summary>Eksik evrak ve compliance görünümü neden önemlidir?</summary>\n      <p>İK ekiplerinin öncelikleri daha net görmesini, belge tamamlama süreçlerini hızlandırmasını ve uyum risklerini daha erken fark etmesini sağlar.</p>\n    </details>\n  </div>\n</section>\n\n<section class="section final-cta reveal-on-scroll">\n  <div class="contact-card">\n    <div>\n      <p class="eyebrow">HAZIR MISINIZ?</p>\n      <h2>Belge ve izin süreçlerinizi daha kontrollü hale getirin.</h2>\n      <p>CADRO ile dijital özlük ve çalışan operasyonlarını tek platformda yönetin.</p>\n    </div>\n    <div class="contact-actions">\n      <a class="primary-button" href="pricing.html" data-i18n-key="btn_view_plans"></a>\n      <a class="ghost-button" href="mailto:info@cadro.io">Satış Ekibine Ulaş</a>\n    </div>\n  </div>\n</section>\n    `,"excel-vs-cadro":`<section class="hero reveal-on-scroll is-visible" style="padding-top: 60px;">\n          <div class="hero-copy">\n            <p class="eyebrow">DİJİTAL DÖNÜŞÜM</p>\n            <h1>Excel tablolarında boğulmayı bırakın.<br><span>Gerçek İK yazılımına geçin.</span></h1>\n            <p class="hero-text">Manuel hesaplamalar, hatalı formüller ve güvenlik risklerinden çıkın. Verilerin gerçekten konuştuğu otomatik bir İK sistemine geçin.</p>\n            <div class="hero-actions">\n              <a class="primary-button" href="pricing.html" data-i18n-key="btn_view_plans"></a>\n            </div>\n          </div>\n          <div class="hero-panel">\n            <figure class="hero-screenshot">\n              <img src="./assets/screenshots/phase2/tr/dashboard.webp" alt="CADRO Otomasyon Ekranı" class="product-shot" style="border-radius: 12px; box-shadow: 0 20px 40px rgba(0,0,0,0.1); filter: hue-rotate(15deg);" />\n            </figure>\n          </div>\n        </section>\n\n        <section class="strip reveal-on-scroll" style="margin-top: 40px;">\n          <div>\n            <span class="strip-label">Geçmiş (Excel)</span>\n            <p>Veriler ayrı sayfalarda yaşar. Biri izin aldığında puantaj otomatik güncellenmez.</p>\n          </div>\n          <div>\n            <span class="strip-label">Gelecek (CADRO)</span>\n            <p>Her şey entegre. İzin onaylandığı anda takvim güncellenir ve bordro hazırlığı otomatikleşir.</p>\n          </div>\n          <div>\n            <span class="strip-label">Kazanç</span>\n            <p>Sıfır hesaplama hatası ve stratejik İK işleri için büyük bir zaman bütçesi.</p>\n          </div>\n        </section>\n\n        <section class="section reveal-on-scroll">\n          <div class="section-head narrow">\n            <p class="eyebrow">KARŞILAŞTIRMA</p>\n            <h2>Neden gerçek bir İK yazılımına geçmelisiniz?</h2>\n          </div>\n          <div class="card-grid" style="grid-template-columns: repeat(3, minmax(0, 1fr));">\n            <article class="feature-card">\n              <h3>Sıfır Formül Hatası</h3>\n              <p>Excel’de tek bir satır kayması bordroyu bozar. CADRO hesaplamaları her zaman doğru.</p>\n            </article>\n            <article class="feature-card">\n              <h3>Banka Seviyesinde Güvenlik</h3>\n              <p>.xlsx dosyası yerine, verileriniz şifrelenir ve KVKK uyumlu bulutta saklanır.</p>\n            </article>\n            <article class="feature-card">\n              <h3>Personel Self‑Service Erişimi</h3>\n              <p>Excel çalışan verisini güvenle açamaz. Cadro, her çalışana sadece kendi kayıtlarını görebileceği güvenli panel verir.</p>\n            </article>\n          </div>\n        </section>\n\n        <section class="section reveal-on-scroll" style="background: #f8fafc; padding: 60px 20px;">\n          <div class="section-head narrow">\n            <p class="eyebrow">SSS</p>\n            <h2>Sıkça Sorulan Sorular</h2>\n          </div>\n          <div class="seo-faq">\n            <details>\n              <summary>Excel neden İK yönetimi için yetersizdir?</summary>\n              <p>Excel güçlü bir araçtır ama veritabanı veya otomasyon sistemi değildir. Formül hatalarına açıktır, denetim kaydı yoktur ve çalışan sayısı arttıkça yavaşlar.</p>\n            </details>\n            <details>\n              <summary>Excel'deki verilerimizi CADRO'ya taşıyabilir miyiz?</summary>\n              <p>Evet. Akıllı içe aktarma aracıyla çalışan listeleri, departmanlar ve geçmiş izin bakiyelerini tek bir Excel şablonuyla dakikalar içinde aktarabilirsiniz.</p>\n            </details>\n          </div>\n        </section>\n\n        <section class="section final-cta reveal-on-scroll">\n          <div class="contact-card">\n            <div>\n              <p class="eyebrow">HAZIR MISINIZ?</p>\n              <h2>Manuel operasyonları geride bırakın.</h2>\n            </div>\n            <div class="contact-actions">\n              <a class="primary-button" href="pricing.html" data-i18n-key="btn_view_plans"></a>\n              <a class="ghost-button" href="mailto:info@cadro.io">Satış Ekibiyle İletişim</a>\n            </div>\n          </div>\n        </section>`,"ik-sozlugu":`<section class="hero reveal-on-scroll is-visible" style="padding-top: 60px; padding-bottom: 40px; text-align: center;">\n          <div class="hero-copy" style="max-width: 800px; margin: 0 auto; text-align: center;">\n            <p class="eyebrow">İNSAN KAYNAKLARI KÜTÜPHANESİ</p>\n            <h1>İK dünyasının ortak dili: <br><span>Kapsamlı İK Sözlüğü</span></h1>\n            <p class="hero-text" style="text-align: center;">A'dan Z'ye en çok kullanılan insan kaynakları terimleri, yasal kavramlar ve performans metriklerinin anlaşılır tanımlarını keşfedin.</p>\n          </div>\n        </section>\n\n        <section class="section reveal-on-scroll" style="background: #f8fafc; padding: 60px 20px;">\n          <div class="glossary-grid">\n            <article class="glossary-card">\n              <h3>Puantaj</h3>\n              <p>Çalışanların gün içinde işe giriş ve çıkış saatlerinin, mola ve mesailerinin kayıt altına alınarak bordro hakedişlerinin hesaplanması işlemidir.</p>\n            </article>\n            <article class="glossary-card">\n              <h3>Turnover (Devir Hızı)</h3>\n              <p>Belirli bir dönemde şirketten ayrılan personelin oranını ifade eder. Yüksek turnover, şirket kültürü veya maaş politikasındaki sorunlara işaret edebilir.</p>\n            </article>\n            <article class="glossary-card">\n              <h3>işe giriş (İşe Uyum)</h3>\n              <p>Yeni işe alınan bir çalışanın şirket kültürüne, ekibine ve araçlarına hızlıca adapte olması için uygulanan planlı ve aşamalı oryantasyon sürecidir.</p>\n            </article>\n            <article class="glossary-card">\n              <h3>OKR (Hedefler ve Kilit Sonuçlar)</h3>\n              <p>Şirketin iddialı vizyonunu ölçülebilir alt hedeflere bölerek, tüm ekiplerin aynı yöne doğru çalışmasını sağlayan popüler bir hedef belirleme metodolojisidir.</p>\n            </article>\n            <article class="glossary-card">\n              <h3>eNPS</h3>\n              <p>Çalışan Net Tavsiye Skoru. Ekiplerinze "Şirketimizi bir arkadaşınıza çalışması için tavsiye eder misiniz?" sorusunu sorarak ölçülen içerideki sadakat metriğidir.</p>\n            </article>\n            <article class="glossary-card">\n              <h3>Kıdem Tazminatı</h3>\n              <p>En az 1 yıl çalışmış personelin işten haksız yere çıkarılması veya yasal istisnalarla ayrılması durumunda, çalıştığı yıl başına aldığı brüt ücrettir.</p>\n            </article>\n            <article class="glossary-card">\n              <h3>işten çıkış (İşten Çıkış)</h3>\n              <p>Çalışanın şirketten ayrılma kararı aldıktan sonra ekipman teslimi, hakların ödenmesi ve çıkış mülakatı gibi yasal ve operasyonel süreçlerin tamamıdır.</p>\n            </article>\n            <article class="glossary-card">\n              <h3>360 Derece Değerlendirme</h3>\n              <p>Bir çalışanın performansının sadece yöneticisi tarafından değil; astları, eşdeğer çalışma arkadaşları ve hatta müşterileri tarafından anonim puanlanmasıdır.</p>\n            </article>\n            <article class="glossary-card">\n              <h3>ATS (Aday Takip Sistemi)</h3>\n              <p>İşe alım sürecini dijitalleştiren, CV'leri toplayan ve mülakat aşamalarını tek bir yazılım üzerinden yönetmeye yarayan İK aracıdır.</p>\n            </article>\n          </div>\n        </section>\n\n        <section class="section final-cta reveal-on-scroll">\n          <div class="contact-card" style="text-align: center;">\n            <div>\n              <p class="eyebrow">TEORİYİ PRATİİE DÖKÜN</p>\n              <h2>İK süreçlerinizi manuel yönetmekten sıkıldınız mı?</h2>\n              <p>Sözlükteki tüm bu süreçleri CADRO ile tek ekrandan, bulut tabanlı ve otomatik olarak yönetebilirsiniz.</p>\n            </div>\n            <div class="contact-actions" style="justify-content: center;">\n              <a class="primary-button" href="pricing.html" data-i18n-key="btn_view_plans"></a>\n            </div>\n          </div>\n        </section>\n    `,"ik-yazilimi":`<section class="section" style="margin-top: 40px;">\n          <div class="section-head">\n            <p class="eyebrow">KAPSAMLI REHBER</p>\n            <h1>İnsan Kaynakları (İK) Yazılımı Nedir?</h1>\n            <p>İK yazılımı (HRMS), işe alım, özlük, izin, puantaj, performans ve çalışan verilerini tek platformda yöneten bulut tabanlı bir sistemdir. CADRO ile işe alım döngüsü hızlanır, İK operasyonel verimliliği artar ve tüm çalışan verisi tek merkezde toplanır. İK yazılımı seçim kriterlerini aşağıda inceleyin.</p>\n          </div>\n\n          <div class="card-grid" style="grid-template-columns: repeat(3, minmax(0, 1fr)); margin-bottom: 32px;">\n            <article class="feature-card"><h3>İK yazılımı ne işe yarar?</h3><p>Çalışan verilerini tek merkezde toplar, onay akışlarını hızlandırır ve manuel takip yükünü azaltır.</p></article>\n            <article class="feature-card"><h3>Kimler kullanır?</h3><p>İK ekipleri, yöneticiler ve operasyon liderleri işe alımdan performansa kadar farklı süreçlerde kullanır.</p></article>\n            <article class="feature-card"><h3>Seçerken nelere bakılmalı?</h3><p>Modül kapsamı, güvenlik, mevzuat uyumu, raporlama ve kullanım kolaylığı öncelikli değerlendirme alanlarıdır.</p></article>\n          </div>\n\n          <section class="section reveal-on-scroll" style="padding-top: 10px;">\n            <div class="section-head narrow">\n              <h2>İK yazılımı ne işe yarar?</h2>\n              <p>İnsan kaynakları yazılımı; çalışan bilgilerinin tek yerde tutulmasını, izin ve puantaj akışlarının daha düzenli yönetilmesini, işe alım ve performans süreçlerinin raporlanmasını sağlar. Böylece ekipler Excel dosyaları ve dağınık e-posta zincirleri yerine tek bir sistem üzerinden çalışır.</p>\n            </div>\n            <div class="card-grid" style="grid-template-columns: repeat(3, minmax(0, 1fr));">\n              <article class="feature-card"><h3>Merkezi çalışan verisi</h3><p>Personel kartları, departman yapısı, belgeler ve izin geçmişi aynı veri modeli içinde tutulur.</p></article>\n              <article class="feature-card"><h3>Daha hızlı operasyon</h3><p>Onay akışları, işe alım adımları ve puantaj süreçleri aynı yapı içinde ilerlediği için operasyonel sürtünme azalır.</p></article>\n              <article class="feature-card"><h3>Daha iyi görünürlük</h3><p>Yöneticiler ve İK ekipleri hangi süreçte ne olduğunu raporlar ve panolar üzerinden daha net izler.</p></article>\n            </div>\n          </section>\n\n          <div class="showcase-stack">\n            <article class="showcase-row">\n              <div class="showcase-copy">\n                <p class="eyebrow">MODÜL 1</p>\n                <h3>Ana Panel (Dashboard)</h3>\n                <p>Tüm İK verilerinize tek ekrandan ulaşın. Çalışan sayısı, izin durumları, açık pozisyonlar ve performans özetlerini canlı panolarla takip edin.</p>\n              </div>\n              <div class="showcase-media">\n                <img src="./assets/screenshots/modules/tr/dashboard.webp" alt="CADRO Ana Panel" class="product-shot" />\n              </div>\n            </article>\n\n            <article class="showcase-row reverse">\n              <div class="showcase-copy">\n                <p class="eyebrow">MODÜL 2</p>\n                <h3>Çalışan Yönetimi</h3>\n                <p>Tüm çalışan bilgilerini tek merkezde yönetin. Kişisel bilgiler, departman atamaları, pozisyon geçmişi ve iletişim detayları her zaman güncel kalsın.</p>\n              </div>\n              <div class="showcase-media">\n                <img src="./assets/screenshots/modules/tr/employees.webp" alt="Çalışan Yönetimi" class="product-shot" />\n              </div>\n            </article>\n\n            <article class="showcase-row">\n              <div class="showcase-copy">\n                <p class="eyebrow">MODÜL 3</p>\n                <h3>Organizasyon Şeması</h3>\n                <p>Şirket yapınızı görsel olarak haritalayın. Departmanlar, raporlama hatları ve ekip yapısı dinamik organizasyon şemasında otomatik güncellenir.</p>\n              </div>\n              <div class="showcase-media">\n                <img src="./assets/screenshots/modules/tr/org-chart.webp" alt="Organizasyon Şeması" class="product-shot" />\n              </div>\n            </article>\n\n            <article class="showcase-row reverse">\n              <div class="showcase-copy">\n                <p class="eyebrow">MODÜL 4</p>\n                <h3>İşe Alım ve Aday Takip Sistemi (ATS)</h3>\n                <p>İlan çıkmaktan teklif mektubuna kadar tüm süreci yönetin. Adayları havuzda toplayın, mülakat takvimlerini otomatikleştirin ve işe alım süresini kısaltın.</p>\n                <a href="ats-ise-alim-yazilimi.html" style="color: var(--cyan); font-weight: 800; display: inline-block; margin-top: 10px;">ATS Modülünü İncele →</a>\n              </div>\n              <div class="showcase-media">\n                <img src="./assets/screenshots/modules/tr/ats.webp" alt="ATS Yazılımı" class="product-shot" />\n              </div>\n            </article>\n\n            <article class="showcase-row">\n              <div class="showcase-copy">\n                <p class="eyebrow">MODÜL 5</p>\n                <h3>İşe Alıştırma (Onboarding)</h3>\n                <p>Yeni çalışanların ilk gününden itibaren sistematik bir başlangıç yapmasını sağlayın. Görev listeleri, belge toplama ve oryantasyon adımlarını otomatikleştirin.</p>\n                <a href="kurumsal-bilgi-bankasi-ve-onboarding.html" style="color: var(--cyan); font-weight: 800; display: inline-block; margin-top: 10px;">Onboarding Modülünü İncele →</a>\n              </div>\n              <div class="showcase-media">\n                <img src="./assets/screenshots/modules/tr/onboarding.webp" alt="Onboarding" class="product-shot" />\n              </div>\n            </article>\n\n            <article class="showcase-row reverse">\n              <div class="showcase-copy">\n                <p class="eyebrow">MODÜL 6</p>\n                <h3>Dijital Özlük Dosyası</h3>\n                <p>Çalışan evraklarını bulut ortamında KVKK uyumlu saklayın. Sözleşmeler, kimlik belgeleri ve sertifikalar dijital özlük dosyasında güvenle arşivlenir.</p>\n                <a href="dijital-ozluk-ve-izin.html" style="color: var(--cyan); font-weight: 800; display: inline-block; margin-top: 10px;">Özlük Modülünü İncele →</a>\n              </div>\n              <div class="showcase-media">\n                <img src="./assets/screenshots/modules/tr/e-dossier.webp" alt="Dijital Özlük Dosyası" class="product-shot" />\n              </div>\n            </article>\n\n            <article class="showcase-row">\n              <div class="showcase-copy">\n                <p class="eyebrow">MODÜL 7</p>\n                <h3>İzin Yönetimi</h3>\n                <p>İzin taleplerini mobil cihazdan gönderin, tek tıkla onaylayın. Kalan izin bakiyeleri, geçmiş talepler ve puantaj entegrasyonu otomatik çalışır.</p>\n                <a href="dijital-ozluk-ve-izin.html" style="color: var(--cyan); font-weight: 800; display: inline-block; margin-top: 10px;">İzin Modülünü İncele →</a>\n              </div>\n              <div class="showcase-media">\n                <img src="./assets/screenshots/modules/tr/leaves.webp" alt="İzin Yönetimi" class="product-shot" />\n              </div>\n            </article>\n\n            <article class="showcase-row reverse">\n              <div class="showcase-copy">\n                <p class="eyebrow">MODÜL 8</p>\n                <h3>Puantaj ve Vardiya Yönetimi</h3>\n                <p>Çalışma saatlerini, vardiya planlarını ve mesai hesaplamalarını dijital ortamda yönetin. Sağlık raporu ve devamsızlık takibi dahil.</p>\n                <a href="puantaj-ve-vardiya-yazilimi.html" style="color: var(--cyan); font-weight: 800; display: inline-block; margin-top: 10px;">Puantaj Modülünü İncele →</a>\n              </div>\n              <div class="showcase-media">\n                <img src="./assets/screenshots/modules/tr/attendance.webp" alt="Puantaj ve Vardiya" class="product-shot" />\n              </div>\n            </article>\n\n            <article class="showcase-row">\n              <div class="showcase-copy">\n                <p class="eyebrow">MODÜL 9</p>\n                <h3>Performans Yönetimi (OKR ve 360°)</h3>\n                <p>Şirket hedefleriyle bireysel hedefleri (OKR) bağlayın. 360° geri bildirim, yetkinlik değerlendirme ve AI destekli analizlerle sürekli performans takibi yapın.</p>\n                <a href="performans-degerlendirme-okr.html" style="color: var(--cyan); font-weight: 800; display: inline-block; margin-top: 10px;">Performans Modülünü İncele →</a>\n              </div>\n              <div class="showcase-media">\n                <img src="./assets/screenshots/modules/tr/performance.webp" alt="Performans Yönetimi" class="product-shot" />\n              </div>\n            </article>\n\n            <article class="showcase-row reverse">\n              <div class="showcase-copy">\n                <p class="eyebrow">MODÜL 10</p>\n                <h3>Eğitim Yönetimi</h3>\n                <p>Çalışan gelişim programlarını planlayın ve takip edin. Eğitim takvimi, katılım takibi ve sertifika yönetimini tek sistemde yürütün.</p>\n              </div>\n              <div class="showcase-media">\n                <img src="./assets/screenshots/modules/tr/training.webp" alt="Eğitim Yönetimi" class="product-shot" />\n              </div>\n            </article>\n\n            <article class="showcase-row">\n              <div class="showcase-copy">\n                <p class="eyebrow">MODÜL 11</p>\n                <h3>Kurumsal Bilgi Bankası</h3>\n                <p>Şirket içi politika, prosedür ve kılavuzları merkezi bir bilgi bankasında yayınlayın. Çalışanlar ihtiyaç duydukları bilgiye anında ulaşsın.</p>\n                <a href="kurumsal-bilgi-bankasi-ve-onboarding.html" style="color: var(--cyan); font-weight: 800; display: inline-block; margin-top: 10px;">Bilgi Bankası Modülünü İncele →</a>\n              </div>\n              <div class="showcase-media">\n                <img src="./assets/screenshots/modules/tr/knowledge-base.webp" alt="Kurumsal Bilgi Bankası" class="product-shot" />\n              </div>\n            </article>\n\n            <article class="showcase-row reverse">\n              <div class="showcase-copy">\n                <p class="eyebrow">MODÜL 12</p>\n                <h3>Masraf Yönetimi</h3>\n                <p>Çalışan masraf taleplerini dijital ortamda toplayın, onay akışlarıyla yönetin. Fiş ve fatura ekleri ile birlikte raporlayın.</p>\n                <a href="masraf-ve-satin-alma.html" style="color: var(--cyan); font-weight: 800; display: inline-block; margin-top: 10px;">Masraf Modülünü İncele →</a>\n              </div>\n              <div class="showcase-media">\n                <img src="./assets/screenshots/modules/tr/expenses.webp" alt="Masraf Yönetimi" class="product-shot" />\n              </div>\n            </article>\n\n            <article class="showcase-row">\n              <div class="showcase-copy">\n                <p class="eyebrow">MODÜL 13</p>\n                <h3>Satın Alma Talepleri</h3>\n                <p>Departman bazlı satın alma taleplerini oluşturun, onay zincirine gönderin ve tedarik süreçlerini şeffaf biçimde yönetin.</p>\n                <a href="masraf-ve-satin-alma.html" style="color: var(--cyan); font-weight: 800; display: inline-block; margin-top: 10px;">Satın Alma Modülünü İncele →</a>\n              </div>\n              <div class="showcase-media">\n                <img src="./assets/screenshots/modules/tr/purchase-requests.webp" alt="Satın Alma Talepleri" class="product-shot" />\n              </div>\n            </article>\n\n            <article class="showcase-row reverse">\n              <div class="showcase-copy">\n                <p class="eyebrow">MODÜL 14</p>\n                <h3>Zimmet ve Demirbaş Yönetimi</h3>\n                <p>Çalışanlara teslim edilen cihaz, ekipman ve demirbaşları kayıt altına alın. Zimmet geçmişi, iade takibi ve envanter durumunu anlık görün.</p>\n              </div>\n              <div class="showcase-media">\n                <img src="./assets/screenshots/modules/tr/assets.webp" alt="Zimmet ve Demirbaş" class="product-shot" />\n              </div>\n            </article>\n\n            <article class="showcase-row">\n              <div class="showcase-copy">\n                <p class="eyebrow">MODÜL 15</p>\n                <h3>Lokasyon Yönetimi</h3>\n                <p>Çok lokasyonlu yapınızı merkezi olarak yönetin. Ofisler, şubeler ve sahalar arası çalışan dağılımını, kapasite ve varlık bilgilerini takip edin.</p>\n              </div>\n              <div class="showcase-media">\n                <img src="./assets/screenshots/modules/tr/locations.webp" alt="Lokasyon Yönetimi" class="product-shot" />\n              </div>\n            </article>\n\n            <article class="showcase-row reverse">\n              <div class="showcase-copy">\n                <p class="eyebrow">MODÜL 16</p>\n                <h3>Talep Formları</h3>\n                <p>Özelleştirilebilir talep formlarıyla çalışan taleplerini standartlaştırın. İzin dışı tüm talepleri (avans, evrak, referans mektubu vb.) tek kanaldan yönetin.</p>\n              </div>\n              <div class="showcase-media">\n                <img src="./assets/screenshots/modules/tr/request-forms.webp" alt="Talep Formları" class="product-shot" />\n              </div>\n            </article>\n\n            <article class="showcase-row">\n              <div class="showcase-copy">\n                <p class="eyebrow">MODÜL 17</p>\n                <h3>Destek Merkezi</h3>\n                <p>Çalışanların İK ekibine soru ve taleplerini iletebildiği dahili destek sistemi. Ticket takibi, önceliklendirme ve yanıt süreleri ile İK operasyonlarını ölçümleyin.</p>\n              </div>\n              <div class="showcase-media">\n                <img src="./assets/screenshots/modules/tr/support-center.webp" alt="Destek Merkezi" class="product-shot" />\n              </div>\n            </article>\n          </div>\n          <section class="section reveal-on-scroll" style="padding-top: 10px;">\n            <div class="section-head narrow">\n              <h2>Hangi şirketler için uygundur?</h2>\n              <p>İK yazılımı yalnızca büyük kurumsal yapılar için değil; hızlı büyüyen ekipler, çok lokasyonlu şirketler, saha çalışanı bulunan organizasyonlar ve süreçlerini standartlaştırmak isteyen KOBİ’ler için de güçlü bir çözümdür.</p>\n            </div>\n            <div class="card-grid" style="grid-template-columns: repeat(3, minmax(0, 1fr));">\n              <article class="feature-card"><h3>KOBİ'ler</h3><p>İzin, özlük ve puantaj takibini daha düzenli hale getirmek isteyen ekipler için uygundur.</p></article>\n              <article class="feature-card"><h3>Büyüyen şirketler</h3><p>İşe alım, işe giriş ve performans süreçlerini ölçeklenebilir hale getirmek isteyen yapılar için idealdir.</p></article>\n              <article class="feature-card"><h3>Çok lokasyonlu operasyonlar</h3><p>Vardiya, puantaj ve belge yönetiminde merkezi kontrol arayan şirketlerde daha yüksek değer üretir.</p></article>\n            </div>\n          </section>\n\n          <section class="section reveal-on-scroll" style="padding-top: 10px;">\n            <div class="section-head narrow">\n              <h2>Excel ile farkı nedir?</h2>\n              <p>Excel listeleri veri tutabilir; ancak izin, puantaj, belge, işe alım ve performans süreçlerini birbirine bağlı şekilde yönetemez. İK yazılımı ise bu akışları tek veri modeli üzerinde birleştirir.</p>\n            </div>\n            <div class="card-grid" style="grid-template-columns: repeat(3, minmax(0, 1fr)); margin-bottom: 28px;">\n              <article class="feature-card"><h3>Excel</h3><p>Liste tutar; fakat iş akışlarını, yetkileri ve onay adımlarını doğal olarak yönetmez.</p></article>\n              <article class="feature-card"><h3>İK yazılımı</h3><p>Veriyi süreçle birleştirir; izin, puantaj, belge ve işe alım adımları aynı yapı içinde ilerler.</p></article>\n              <article class="feature-card"><h3>Yönetim farkı</h3><p>Raporlama, görünürlük ve ekipler arası koordinasyon için daha güvenilir bir temel sunar.</p></article>\n            </div>\n          </section>\n\n          <section class="section reveal-on-scroll" style="padding-top: 10px;">\n            <div class="section-head narrow">\n              <h2>İK yazılımı seçerken nelere dikkat edilmeli?</h2>\n              <p>Her yazılım aynı yapıda değildir. Değerlendirme yaparken modül derinliği, kullanım kolaylığı, mevzuat uyumu, güvenlik, raporlama ve iç entegrasyon gücü birlikte ele alınmalıdır.</p>\n            </div>\n            <div class="faq-wrap">\n              <div class="faq-card"><h3>Modül kapsamı</h3><p>ATS, özlük, izin, puantaj, performans ve talep akışları aynı ürün içinde ne kadar güçlü çalışıyor?</p></div>\n              <div class="faq-card"><h3>Mevzuat ve güvenlik</h3><p>KVKK uyumu, rol bazlı erişim ve denetim izi gibi konular net biçimde tanımlanmalı.</p></div>\n              <div class="faq-card"><h3>Kullanım kolaylığı</h3><p>İK ekibi kadar yöneticiler ve çalışanlar için de sade ve uygulanabilir bir deneyim sunmalı.</p></div>\n            </div>\n          </section>\n\n          <section class="section reveal-on-scroll" style="padding-top: 10px;">\n            <div class="section-head narrow">\n              <h2>Sık sorulan sorular</h2>\n            </div>\n            <div class="faq-wrap">\n              <div class="faq-card"><h3>İK yazılımı ile personel yönetim yazılımı aynı şey mi?</h3><p>Çoğu zaman benzer şekilde kullanılır; ancak kapsamlı bir İK yazılımı işe alım, izin, puantaj, performans ve belge akışlarını da kapsar.</p></div>\n              <div class="faq-card"><h3>İK yazılımı fiyatı neye göre değişir?</h3><p>Modül kapsamı, şirket ölçeği, raporlama ihtiyaçları ve destek seviyesi fiyatlandırmada belirleyici olur.</p></div>\n              <div class="faq-card"><h3>Türkiye’de mevzuat açısından neden önemlidir?</h3><p>Belge yönetimi, izin kayıtları, rol bazlı erişim ve denetim izi gibi başlıklar şirket içi düzen ve uyum açısından önem taşır.</p></div>\n            </div>\n            <div class="contact-actions" style="justify-content:center;">\n              <a class="primary-button" href="pricing.html">Fiyatları İncele</a>\n              <a class="ghost-button" href="blog.html">Blog Yazılarını Oku</a>\n              <a class="ghost-button" href="vaka-calismalari.html">Vaka Çalışmalarını Gör</a>\n              <a class="ghost-button" href="faq.html">SSS'ye Git</a>\n            </div>\n          </section>\n        </section>\n    `,"kurumsal-bilgi-bankasi-ve-onboarding":`<section class="hero reveal-on-scroll is-visible" style="padding-top: 60px;">\n  <div class="hero-copy">\n    <p class="eyebrow">KURUMSAL BİLGİ BANKASI & işe giriş</p>\n    <h1>Politikaları, SOP’leri ve işe giriş akışlarını <br><span>tek merkezde yönetin.</span></h1>\n    <p class="hero-text">Kurumsal bilgi bankası ile şirket politikalarını versiyon kontrollü yayınlayın, okundu/onaylandı kayıtlarını görün ve yeni çalışanların adaptasyon sürecini standart bir iş akışına dönüştürün. CADRO ile onboarding süresi kısalır ve kurumsal hafıza merkezileşir.</p>\n     <div class="hero-actions">\n       <a class="primary-button" href="pay.html?plan=growth&billing=monthly">Pro Planı İncele</a>\n       <a class="ghost-button" href="#ozellikler">Nasıl Çalışır?</a>\n    </div>\n  </div>\n  <div class="hero-panel">\n    <figure class="hero-screenshot">\n      <img src="./assets/screenshots/phase5/tr/knowledge-base.webp" alt="CADRO kurumsal bilgi bankası ve politika yönetimi ekranı" class="product-shot" loading="eager" fetchpriority="high" style="border-radius: 12px; box-shadow: 0 20px 40px rgba(0,0,0,0.1);" />\n    </figure>\n  </div>\n</section>\n\n<section class="strip reveal-on-scroll" style="margin-top: 40px;">\n  <div>\n    <span class="strip-label">İK Perspektifi</span>\n    <p>Politikaların tek noktadan yayınlanması, çalışan iletişimini standardize eder ve işe giriş yükünü azaltır.</p>\n  </div>\n  <div>\n    <span class="strip-label">Operasyon Perspektifi</span>\n    <p>Departman, rol veya çalışan bazlı hedefleme ile her içerik doğru kişiye doğru versiyonla ulaşır.</p>\n  </div>\n  <div>\n    <span class="strip-label">CADRO Çözümü</span>\n    <p>Bilgi bankası, okundu onayı, versiyon geçmişi ve işe giriş görevleri aynı iş akışında birleşir.</p>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll" id="ozellikler">\n  <div class="section-head narrow">\n    <p class="eyebrow">MODÜL ÖZELLİKLERİ</p>\n    <h2>Kurumsal bilgiyi daha görünür, daha izlenebilir ve daha sürdürülebilir hale getirin</h2>\n  </div>\n  <div class="card-grid" style="grid-template-columns: repeat(3, minmax(0, 1fr));">\n    <article class="feature-card">\n      <h3>Versiyonlu Politika Yönetimi</h3>\n      <p>Her politika ve SOP güncellemesini sürüm bazında izleyin, eski versiyonları arşivleyin ve yeni onay akışlarını tetikleyin.</p>\n    </article>\n    <article class="feature-card">\n      <h3>Okundu & Onaylandı Takibi</h3>\n      <p>Hangi içeriğin kim tarafından okunduğunu ve hangi çalışanların hâlâ aksiyon vermediğini net biçimde görün.</p>\n    </article>\n    <article class="feature-card">\n      <h3>işe giriş Şablonları</h3>\n      <p>İlk gün, ilk hafta ve ilk ay görevlerini departman ya da rol bazlı kurgulayarak işe giriş deneyimini standardize edin.</p>\n    </article>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll">\n  <div class="showcase-stack">\n    <article class="showcase-row">\n      <div class="showcase-copy">\n        <p class="eyebrow">POLICY ACKNOWLEDGEMENT</p>\n        <h3>Politika yayını, hedefleme ve çalışan onayı tek akışta</h3>\n        <p>Şirket geneli, rol, departman veya kişi bazlı hedefleme yapın. Böylece kritik içerikleri rastgele paylaşmak yerine kontrollü bir kurumsal bilgi dağıtım yapısı kurun.</p>\n        <a href="compliance.html" style="color: var(--cyan); font-weight: 800; display: inline-block; margin-top: 10px;">Uyumluluk yapısını incele →</a>\n      </div>\n      <div class="showcase-media">\n        <img src="./assets/screenshots/phase5/tr/knowledge-base-modal.webp" alt="CADRO yeni politika ve bilgi makalesi ekleme ekranı" class="product-shot" loading="lazy" />\n      </div>\n    </article>\n    <article class="showcase-row reverse">\n      <div class="showcase-copy">\n        <p class="eyebrow">ONBOARDING ORKESTRASYONU</p>\n        <h3>Yeni çalışan adaptasyonunu kişilere değil sisteme bağlayın</h3>\n        <p>işe giriş görevlerini standartlaştırarak İK, IT ve operasyon ekipleri arasında daha tutarlı, daha hızlı ve daha ölçülebilir bir ilk gün deneyimi oluşturun.</p>\n        <a href="security.html" style="color: var(--cyan); font-weight: 800; display: inline-block; margin-top: 10px;">Güvenlik yaklaşımını incele →</a>\n      </div>\n      <div class="showcase-media">\n        <img src="./assets/screenshots/phase5/tr/onboarding.webp" alt="CADRO işe giriş ve görev takibi ekranı" class="product-shot" loading="lazy" />\n      </div>\n    </article>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll" style="background: #f8fafc; padding: 60px 20px;">\n  <div class="section-head narrow">\n    <p class="eyebrow">SIKÇA SORULANLAR</p>\n    <h2>Kurumsal bilgi bankası ve işe giriş ile ilgili temel sorular</h2>\n  </div>\n  <div class="seo-faq">\n    <details>\n      <summary>Politikalar için okundu onayı ve versiyon takibi yapılabiliyor mu?</summary>\n      <p>Evet. Her yeni politika sürümü için hedef kitle belirlenebilir, eski versiyon arşivlenir ve yeni sürüm için tekrar okundu/onaylandı akışı başlatılabilir.</p>\n    </details>\n    <details>\n      <summary>işe giriş görevleri departman veya rol bazında otomatik atanabilir mi?</summary>\n      <p>Evet. İK, IT, operasyon veya yöneticilere ait işe giriş görevleri şablon olarak tanımlanabilir ve yeni çalışan eklenince otomatik başlatılabilir.</p>\n    </details>\n  </div>\n</section>\n\n<section class="section final-cta reveal-on-scroll">\n  <div class="contact-card">\n    <div>\n      <p class="eyebrow">HAZIR MISINIZ?</p>\n      <h2>Kurumsal hafızayı ve çalışan adaptasyonunu aynı sistemde yönetin.</h2>\n    </div>\n    <div class="contact-actions">\n      <a class="primary-button" href="pricing.html">Planları İncele</a>\n      <a class="ghost-button" href="mailto:info@cadro.io">Satış Ekibine Ulaş</a>\n    </div>\n  </div>\n</section>\n\n    `,"makale-ai-ve-kvkk-uyumu":`<article class="article-container reveal-on-scroll is-visible">\n        <div class="article-header">\n          <div class="article-meta">25 Mart 2026 • İK, Hukuk ve Veri Güvenliği</div>\n          <h1 class="article-title">AI vs KVKK İkilemi: Çalışan Verilerini İşlerken Hukuki Riskleri Yönetmek</h1>\n        </div>\n        <div class="article-content">\n          <p>Büyük Dil Modelleri (LLM) ve üretken yapay zeka araçları İK departmanlarına muazzam hız kazandırıyor. Ancak bir çalışanın performans verilerini, sağlık raporlarını veya maaş geçmişini analiz etmesi için üçüncü parti bir yapay zekaya yüklemek, Kişisel Verilerin Korunması Kanunu (KVKK) ve GDPR kapsamında devasa riskler yaratır.</p>\n          \n          <h2>Veri Yerelleştirmesi (Data Localization) Sorunu</h2>\n          <p>Ücretsiz veya açık kaynaklı yapay zeka araçlarının en büyük sorunu, verileri sınır ötesindeki sunucularına taşımasıdır. Kanunlar, kişisel verilerin açık rıza olmadan yurtdışına çıkarılmasını kesin bir dille yasaklar. Bir İK uzmanı, çalışanın performans özetini çıkarmak için verileri bulut tabanlı halka açık bir yapay zekaya (örneğin standart bir ChatGPT ekranına) kopyaladığında, şirket potansiyel olarak milyonlarca liralık veri ihlali cezasıyla karşı karşıya kalır.</p>\n\n          <h2>Hukuk Departmanı ve CHRO Uyumu</h2>\n          <p>Kurumsal seviyede yapay zeka kullanımı için şirketlerin alması gereken önlemler şunlardır:</p>\n          <ul>\n            <li><strong>Kapalı Ekosistem (Closed-Loop) AI:</strong> Şirketler, çalışan verilerini dış dünyayla eğitmeyen, verinin şirket sunucularında veya yerel bulutta şifrelenmiş (Encrypted) olarak işlendiği kurumsal İK yazılımlarını (CADRO gibi) tercih etmelidir.</li>\n            <li><strong>Açık Rıza Yönetimi:</strong> Çalışanların dijital özlük dosyalarında, verilerinin yapay zeka destekli performans ve kariyer planlaması amacıyla işleneceğine dair spesifik dijital rıza (consent) kayıtları tutulmalı ve bu kayıtlar versiyonlanmalıdır.</li>\n            <li><strong>Unutulma Hakkı:</strong> Bir çalışan işten ayrıldığında ve verilerinin silinmesini talep ettiğinde, sistemin bu verileri AI algoritmalarının hafızasından da silebilecek bir mimariye sahip olması gerekir.</li>\n          </ul>\n          \n          <p>Yapay zeka çağında İK liderliği, sadece yeni teknolojileri kullanmayı değil, bu teknolojileri kurumsal veri güvenliği standartlarına entegre etmeyi gerektirir.</p>\n        </div>\n        <div class="article-cta">\n          <h3>KVKK Uyumlu İK Dijitalleşmesi</h3>\n          <p>Verileriniz CADRO'nun banka düzeyinde güvenlik altyapısıyla korunur. Şirketinizi yasal risklerden arındırın.</p>\n          <a href="pricing.html" class="primary-button" style="background: var(--cyan); color: #0f172a;">Güvenlik Altyapımızı İnceleyin</a>\n        </div>\n      </article>\n    `,"makale-dijital-ozluk-ve-kvkk":`<article class="article-container reveal-on-scroll is-visible">\n        <div class="article-header">\n          <div class="article-meta">22 January 2026 • Legal Compliance & HR</div>\n          <h1 class="article-title">Digital Personnel Files & KVKK: Are You Ready When Inspectors Knock?</h1>\n        </div>\n        <div class="article-content">\n          <p>Under Turkish Labor Law Article 75, employers must maintain a personnel file for each employee. Keeping these files in locked cabinets and paper folders creates risks—fire, loss, and most critically, unauthorized access (a KVKK violation).</p>\n          \n          <h2>The Legal Cost of Missing Documents</h2>\n          <p>In an SGK audit or a reinstatement lawsuit, courts first request the employee’s personnel file. An expired medical report, a contract missing signatures, or a lost occupational safety certificate can directly cause a case loss and significant compensation.</p>\n\n          <h2>Audit‑Ready with Digital Archiving</h2>\n          <p>Digital personnel management removes this legal stress entirely. A cloud HR system tracks missing documents or expiring certificates with AI and alerts managers automatically. Secure audit trails record who accessed which document and when—preventing data breaches and ensuring full KVKK compliance.</p>\n        </div>\n        <div class="article-cta">\n          <h3>Move Beyond Paper Files</h3>\n          <p>Reduce operational load with missing‑document alerts and KVKK‑compliant archiving.</p>\n          <a href="dijital-ozluk-ve-izin.html" class="primary-button" style="background: var(--cyan); color: #0f172a;">Explore Personnel Files</a>\n        </div>\n      </article>\n    `,"makale-excel-bordro-sizintilari":`<article class="article-container reveal-on-scroll is-visible">\n        <div class="article-header">\n          <div class="article-meta">05 January 2026 • Finance & Operations</div>\n          <h1 class="article-title">Payroll Leakage: The Hidden Cost of Timesheets in Excel</h1>\n        </div>\n        <div class="article-content">\n          <p>In a company with hundreds of employees, manually merging timekeeping data (clock‑in/out, absences, overtime) in Excel every month is one of the most dangerous risks a CFO can face in the budget.</p>\n          \n          <blockquote>"Payroll leakage is the payment of unearned overtime or the failure to deduct absences due to calculation errors. Studies show that manual timekeeping leaks 2–4% of total payroll."</blockquote>\n          \n          <h2>The Hidden Costs of Excel</h2>\n          <p>Excel sheets are static, can’t sync in real time with attendance devices (badges, biometrics), and are vulnerable to formula errors. One deleted row or a copy‑paste mistake can lead to over‑ or under‑payment. Underpayments destroy trust; overpayments inflate operating expenses.</p>\n\n          <h2>ROI of an Automated, Error‑Free System</h2>\n          <p>With automation, night‑shift multipliers, public‑holiday overtime, and work beyond 45 hours are calculated in seconds according to labor law. Month‑end marathons for HR and Accounting disappear. The payback period of a timekeeping system is often just a few months—covered by the first payroll leakage it stops.</p>\n        </div>\n        <div class="article-cta">\n          <h3>Stop Payroll Leakage Today</h3>\n          <p>Discover an accurate, fully compliant, device‑integrated timekeeping system.</p>\n          <a href="puantaj-ve-vardiya-yazilimi.html" class="primary-button" style="background: var(--cyan); color: #0f172a;">Explore Timekeeping</a>\n        </div>\n      </article>\n    `,"makale-ik-dijital-donusum-2026":`<article class="article-container reveal-on-scroll is-visible">\n        <div class="article-header">\n          <div class="article-meta">10 March 2026 • HR Automation</div>\n          <h1 class="article-title">2026 HR Digital Transformation Guide: From Paperless Office to Data‑Driven Management</h1>\n        </div>\n        <div class="article-content">\n          <p>Many companies think digital transformation is complete when they move employee documents from paper folders to Google Drive or Excel. That’s just a format change. Real transformation begins when systems talk to each other and produce business decisions—not just store data.</p>\n          \n          <h2>Breaking Data Silos</h2>\n          <p>If payroll lives in accounting software, performance reviews in Excel, and hiring in email threads, you have a data‑silo problem. When a CFO asks, “What’s the correlation between our top performers’ cost and the value they produce?”, silos make the answer take weeks.</p>\n          \n          <h2>Cloud (SaaS) Architecture & Total Cost of Ownership (TCO)</h2>\n          <p>On‑premise maintenance, server, and IT staffing costs are no longer sustainable. 2026 HR trends require a full move to cloud (SaaS). When choosing a modern HRMS, look for these three essentials:</p>\n          <ul>\n            <li><strong>Unified Data Architecture:</strong> When an employee takes leave, timekeeping, manager calendars, and payroll entitlements should update simultaneously and automatically.</li>\n            <li><strong>Self‑Service Employee Experience:</strong> HR should not be a call center for “How much leave do I have?”. Employees should manage their data from mobile dashboards.</li>\n            <li><strong>Audit Trail:</strong> Every change should be logged with who/when, in encrypted records—critical for internal audits and regulation.</li>\n          </ul>\n        </div>\n        <div class="article-cta">\n          <h3>Leave Legacy Systems Behind</h3>\n          <p>Excel is not a management system. Meet CADRO and run operations safely from one central source.</p>\n          <a href="excel-vs-cadro.html" class="primary-button" style="background: var(--cyan); color: #0f172a;">Excel vs CADRO</a>\n        </div>\n      </article>\n    `,"makale-ise-alimda-ai-etik":`<article class="article-container reveal-on-scroll is-visible">\n        <div class="article-header">\n          <div class="article-meta">28 March 2026 • HR & AI</div>\n          <h1 class="article-title">AI in Hiring: Eliminating Bias or Deepening It?</h1>\n        </div>\n        <div class="article-content">\n          <p>An AI assistant that scans thousands of CVs and surfaces the top five candidates in seconds is every CHRO’s dream. But that dream carries a major legal and ethical risk: algorithmic bias.</p>\n          \n          <h2>The Black Box Problem</h2>\n          <p>AI models learn from historical data. If a company has mostly hired leaders from a particular school or demographic over the last decade, the model concludes “this is the successful profile.” As a result, it filters out other qualified candidates through an invisible bias.</p>\n\n          <blockquote>"Speed is not an advantage if you’re moving in the wrong direction. HR automation doesn’t replace human judgment—it makes it auditable."</blockquote>\n\n          <h2>Ethical AI That Reduces Bias</h2>\n          <p>Modern ATS platforms mitigate this risk with blind‑recruitment algorithms. To build a competency‑first AI process, C‑level leaders should:</p>\n          <ul>\n            <li><strong>Mask Demographic Data:</strong> Names, age, gender, and photos are hidden while the system evaluates experience, skills, and certifications.</li>\n            <li><strong>Diversity & Inclusion Audits:</strong> Outputs must be tested regularly by human HR experts. AI should be a co‑pilot, not the final judge.</li>\n          </ul>\n          \n          <p>When designed correctly, AI can reduce unconscious bias (halo and horn effects), helping companies build more diverse, innovative teams.</p>\n        </div>\n        <div class="article-cta">\n          <h3>Fair, Data‑Driven Hiring</h3>\n          <p>Use CADRO’s advanced ATS to improve candidate experience while discovering talent without bias.</p>\n          <a href="pricing.html" class="primary-button" style="background: var(--cyan); color: #0f172a;" data-i18n-key="btn_view_plans"></a>\n        </div>\n      </article>\n    `,"makale-prediktif-ik":`<article class="article-container reveal-on-scroll is-visible">\n        <div class="article-header">\n          <div class="article-meta">02 April 2026 • HR & AI</div>\n          <h1 class="article-title">Predictive HR: Algorithms That See Resignations Early</h1>\n        </div>\n        <div class="article-content">\n          <p>Talent loss (turnover) is one of the biggest hidden leaks in modern P&L statements. Studies show replacing a key employee can cost up to 150% of their annual salary. For CFOs and CHROs, this is not just an HR problem—it’s a direct threat to EBITDA targets.</p>\n          \n          <blockquote>"Exit interviews are corporate autopsies. Knowing the cause of death after the patient is gone doesn’t restore operational health."</blockquote>\n          \n          <h2>From Reactive HR to Proactive HR</h2>\n          <p>Traditional HR reacts when a resignation arrives. Predictive HR uses machine learning and analytics to detect risk months in advance. The system analyzes digital footprints anonymously and KVKK‑compliantly to build an engagement score.</p>\n          \n          <h2>How Algorithms Predict Resignations</h2>\n          <p>Smart systems don’t look at single data points but correlations. Early warning signals include:</p>\n          <ul>\n            <li><strong>Overtime Fatigue:</strong> Employees with irregular or excessive overtime over the last three months are flagged for burnout risk.</li>\n            <li><strong>Leave‑Use Anomalies:</strong> A sudden pattern of frequent half‑day or single‑day leaves suggests the employee may be interviewing elsewhere.</li>\n            <li><strong>Performance Feedback Drops:</strong> In 360 reviews, a dip in peer scores after a strong history is a quantitative sign of quiet quitting.</li>\n          </ul>\n\n          <h2>ROI for the C‑Suite</h2>\n          <p>Companies using predictive analytics can reduce turnover by up to 25%. Early alerts let managers intervene with a timely 1‑on‑1, a small rotation, or a benefits update—preventing massive talent‑loss costs.</p>\n        </div>\n        <div class="article-cta">\n          <h3>Discover Predictive Analytics Today</h3>\n          <p>Don’t just store data—make it speak. Turn risks into opportunities with CADRO’s smart reporting.</p>\n          <a href="pricing.html" class="primary-button" style="background: var(--cyan); color: #0f172a;" data-i18n-key="btn_view_plans"></a>\n        </div>\n      </article>\n    `,"makale-sessiz-istifa-maliyeti":`<article class="article-container reveal-on-scroll is-visible">\n        <div class="article-header">\n          <div class="article-meta">18 March 2026 • Culture & Strategy</div>\n          <h1 class="article-title">How Much Is Quiet Quitting Costing Your Company?</h1>\n        </div>\n        <div class="article-content">\n          <p>The most dangerous report on a CEO’s desk isn’t the resignation list—it’s the invisible cost of employees who mentally check out while staying on payroll. Quiet quitting is a culture crisis where people do the bare minimum to avoid being fired.</p>\n          \n          <blockquote>"Gallup finds 59% of employees worldwide are quiet quitting. The global cost is $8.8 trillion—about 9% of global GDP."</blockquote>\n          \n          <h2>Productivity Leakage: The Invisible OPEX Cost</h2>\n          <p>Visible costs (rent, software, gross salaries) are manageable. But if a specialist uses only 40% of their potential, the company pays a massive opportunity cost every month. Communication slows, innovation stalls, and high performers carry more load—until they leave.</p>\n\n          <h2>The Antidote: Transparency and OKRs</h2>\n          <p>Why do employees disengage? Often because they can’t see how daily work connects to company vision. Static KPI targets don’t inspire modern teams.</p>\n          <p><strong>OKRs (Objectives & Key Results)</strong> solve this. When employees see how their work directly moves quarterly goals, belonging returns. When success is recognized continuously—not only at year‑end—quiet quitting gives way to real commitment.</p>\n        </div>\n        <div class="article-cta">\n          <h3>Re‑Energize Your Teams</h3>\n          <p>Broadcast your vision to every level with CADRO’s OKR and 360 feedback modules.</p>\n          <a href="performans-degerlendirme-okr.html" class="primary-button" style="background: var(--cyan); color: #0f172a;">Explore Performance</a>\n        </div>\n      </article>\n    `,"makale-turnover-dusurme-yollari":`<article class="article-container reveal-on-scroll is-visible">\n        <div class="article-header">\n          <div class="article-meta">28 February 2026 • Talent Management</div>\n          <h1 class="article-title">5 Data‑Driven Ways to Reduce High Turnover</h1>\n        </div>\n        <div class="article-content">\n          <p>The biggest misconception is that turnover can be solved with salary increases alone. Data shows 75% of departures are about culture and managers—not the job itself.</p>\n          \n          <blockquote>"Turnover isn’t a disease—it’s a symptom of internal operational issues: poor leadership, unfair evaluations, and lack of vision."</blockquote>\n          \n          <h2>1. A Flawless First 90 Days</h2>\n          <p>The top driver of early turnover (first 6 months) is a poor onboarding experience. If day one is chaotic and week one is unclear, trust erodes fast. A digital onboarding module assigns tasks automatically to every department, making the journey smooth.</p>\n\n          <h2>2. Build Fairness with Data</h2>\n          <p>When promotions and bonuses follow competency matrices, OKRs, and 360 feedback—not managerial bias—perceptions of favoritism disappear. Where fairness is proven, turnover drops dramatically.</p>\n\n          <h2>3. Knowledge Hub & Transparency</h2>\n          <p>When employees must constantly ask HR for policies, leave rights, or benefits, friction grows. A centralized knowledge base democratizes information and builds trust.</p>\n        </div>\n        <div class="article-cta">\n          <h3>Keep Your Talent Inside</h3>\n          <p>Eliminate bad onboarding experiences and show value from day one.</p>\n          <a href="kurumsal-bilgi-bankasi-ve-onboarding.html" class="primary-button" style="background: var(--cyan); color: #0f172a;">Our Onboarding Solution</a>\n        </div>\n      </article>\n    `,"makale-yapay-zeka-genai":`<article class="article-container reveal-on-scroll is-visible">\n          \n          <div class="article-header">\n            <div class="article-meta">05 April 2026 • HR & AI</div>\n            <h1 class="article-title">Save 15 Hours/Week in HR Ops with Generative AI (GenAI)</h1>\n            <div class="article-author">Author: <strong>CADRO Research Team</strong> • Reading Time: 4 minutes</div>\n          </div>\n\n          <div class="article-content">\n            <p>One of the most common C‑level misconceptions is viewing HR as a department that “pays salaries and fills forms.” In reality, modern HR builds culture, uncovers talent, and drives performance as a strategic partner.</p>\n            \n            <p>Yet reality is different: most HR professionals spend <strong>40%</strong> of their time on routine admin tasks—writing job ads, consolidating feedback, answering policy questions. This is where Generative AI (GenAI) frees HR teams from data drudgery.</p>\n\n            <blockquote>\n              "AI won’t replace HR professionals. But HR professionals who use AI will replace those who don’t."\n            </blockquote>\n\n            <h2>1. Hiring Transformation: Save 5 Hours/Week</h2>\n            <p>Writing a great job ad and preparing interviews can take hours. With AI, it takes seconds:</p>\n            <ul>\n              <li><strong>Job Ad Optimization:</strong> Feed role requirements to the AI assistant and get a culture‑fit, inclusive, SEO‑friendly posting in seconds.</li>\n              <li><strong>Personalized Interview Questions:</strong> AI analyzes a candidate’s CV and generates 10 technical questions tailored to their experience gaps and skill sets.</li>\n            </ul>\n\n            <h2>2. Performance Review Analysis: Save 4 Hours/Week</h2>\n            <p>During 360 reviews, managers write countless open‑ended comments about peers and reports. Synthesizing them is a nightmare.</p>\n            <p>GenAI reads dozens of text feedback entries, filters emotional bias, and delivers an objective, data‑based summary of strengths and development areas.</p>\n\n            <h2>3. Internal Comms & Onboarding Assistant: Save 6 Hours/Week</h2>\n            <p><em>"How many days is parental leave?", "What does my private health plan cover?", "Where’s the laptop request form?"</em></p>\n            <p>HR spends hours answering repetitive questions via Slack or email. An AI chatbot connected to your knowledge base and policies answers 24/7, creating a true self‑service employee experience.</p>\n\n            <h2>Financial Impact (ROI)</h2>\n            <p>Simple math: a 3‑person HR team saving 15 hours each per week equals 180 hours per month—essentially <strong>one additional strategic HR manager</strong> worth of capacity. That time can be invested in retention programs and data‑driven initiatives that reduce turnover.</p>\n          </div>\n\n          <div class="article-cta">\n            <h3>Ready to Automate Your HR Operations?</h3>\n            <p>Bring the future forward. CADRO’s intelligent platform frees you from operational load so you can focus on strategy.</p>\n            <a href="pricing.html" class="primary-button" style="background: var(--cyan); color: #0f172a;" data-i18n-key="btn_view_plans"></a>\n          </div>\n\n        </article>\n    `,"makale-yillik-performans-degerlendirme":`<article class="article-container reveal-on-scroll is-visible">\n        <div class="article-header">\n          <div class="article-meta">10 February 2026 • Performance Management</div>\n          <h1 class="article-title">Is the Annual Performance Review Dead?</h1>\n        </div>\n        <div class="article-content">\n          <p>Performance reviews done once a year—usually in December—can’t keep up with the speed of modern work. Leading companies (Adobe, Microsoft, GE) abandoned this archaic system years ago. Why?</p>\n          \n          <blockquote>"Discussing January’s success or June’s mistake in December isn’t management—it’s judgment."</blockquote>\n          \n          <h2>The Recency Bias Trap</h2>\n          <p>Humans remember the most recent events. In annual reviews, managers rate the last two months rather than the whole year. This creates unfair bonuses and deep perceptions of injustice.</p>\n\n          <h2>The Solution: Continuous Feedback & 360 Agility</h2>\n          <p>Management in 2026 means <strong>continuous performance management</strong>—OKRs set quarterly and feedback given in real time. Success shouldn’t depend on a single manager’s opinion; 360 reviews with anonymous peer and report input create a far more transparent competency map.</p>\n        </div>\n        <div class="article-cta">\n          <h3>Build a Fair Performance Culture</h3>\n          <p>Say goodbye to boring forms. Discover CADRO’s 360 review and competency matrix modules.</p>\n          <a href="performans-degerlendirme-okr.html" class="primary-button" style="background: var(--cyan); color: #0f172a;">Explore Performance</a>\n        </div>\n      </article>\n    `,"masraf-ve-satin-alma":`<section class="hero reveal-on-scroll is-visible" style="padding-top: 60px;">\n  <div class="hero-copy">\n    <p class="eyebrow">EXPENSE MANAGEMENT & PURCHASE REQUESTS</p>\n    <h1>Harcamaları, fişleri ve <br><span>satın alma taleplerini tek akışta yönetin.</span></h1>\n    <p class="hero-text">Masraf yönetimi yazılımı ile çalışan masraflarını, fiş ve fatura yüklemelerini, satın alma taleplerini ve onay süreçlerini tek yapı içinde yönetin. CADRO ile finans ve operasyon ekipleri harcama akışını daha görünür, daha kontrollü ve daha denetlenebilir hale getirir.</p>\n     <div class="hero-actions">\n       <a class="primary-button" href="pay.html?plan=growth&billing=monthly">Pro Planı İncele</a>\n       <a class="ghost-button" href="#ozellikler">Modülü Keşfet</a>\n    </div>\n  </div>\n  <div class="hero-panel">\n    <figure class="hero-screenshot">\n      <img src="./assets/screenshots/phase4/tr/expenses.webp" alt="CADRO masraf yönetimi ana ekranı" class="product-shot" loading="eager" fetchpriority="high" style="border-radius: 12px; box-shadow: 0 20px 40px rgba(0,0,0,0.1);" />\n    </figure>\n  </div>\n</section>\n\n<section class="strip reveal-on-scroll" style="margin-top: 40px;">\n  <div>\n    <span class="strip-label">Problem</span>\n    <p>Masraf fişlerinin geç toplanması, satın alma taleplerinin e-posta içinde kaybolması ve onay zincirinin görünmez kalması finansal kontrolü zayıflatır.</p>\n  </div>\n  <div>\n    <span class="strip-label">CADRO Çözümü</span>\n    <p>Masraf kayıtları, satın alma talepleri, kategori bazlı sınıflandırma ve approve/reject akışlarını tek operasyonda birleştiren merkezi yapı.</p>\n  </div>\n  <div>\n    <span class="strip-label">Sonuç</span>\n    <p>Daha hızlı onay, daha güçlü bütçe görünürlüğü ve denetim izi olan daha kurumsal bir harcama yönetimi.</p>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll" id="ozellikler">\n  <div class="section-head narrow">\n    <p class="eyebrow">MODÜL ÖZELLİKLERİ</p>\n    <h2>Masraf ve satın alma süreçlerini standardize edin</h2>\n  </div>\n  <div class="card-grid" style="grid-template-columns: repeat(3, minmax(0, 1fr));">\n    <article class="feature-card">\n      <h3>Masraf Kaydı ve Onay Akışı</h3>\n      <p>Çalışanlar fiş ve fatura yükleyebilir, açıklama ekleyebilir ve kayıtlarını tek akıştan onaya gönderebilir. Bekleyen, onaylanan ve reddedilen kayıtlar net biçimde görünür.</p>\n    </article>\n    <article class="feature-card">\n      <h3>Satın Alma Talep Yönetimi</h3>\n      <p>İhtiyaç kalemlerini, tedarikçi bilgisini, birim maliyeti ve termin tarihini standart bir yapı içinde yönetin. Talep gerekçesi ile karar sürecini güçlendirin.</p>\n    </article>\n    <article class="feature-card">\n      <h3>Denetim İzi ve Bütçe Görünürlüğü</h3>\n      <p>Her harcama ve talebin kim tarafından açıldığı, hangi aşamada onaylandığı ve bordroya neyin aktarıldığı daha görünür hale gelir.</p>\n    </article>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll">\n  <div class="showcase-stack">\n    <article class="showcase-row">\n      <div class="showcase-copy">\n        <p class="eyebrow">MASRAF GİRİŞ AKIŞI</p>\n        <h3>Fiş ve fatura girişini çalışan deneyimiyle uyumlu hale getirin</h3>\n        <p>Kategori seçimi, tutar, para birimi, açıklama ve belge yükleme adımları tek form içinde ilerler. Böylece çalışanlar daha düzenli kayıt açar, finans ekipleri daha temiz veri ile çalışır.</p>\n        <a href="puantaj-ve-vardiya-yazilimi.html" style="color: var(--cyan); font-weight: 800; display: inline-block; margin-top: 10px;">Puantaj ve Payroll Görünürlüğünü İncele →</a>\n      </div>\n      <div class="showcase-media">\n        <img src="./assets/screenshots/phase4/tr/expenses-modal.webp" alt="CADRO yeni masraf girişi modal ekranı" class="product-shot" loading="lazy" />\n      </div>\n    </article>\n    <article class="showcase-row">\n      <div class="showcase-copy">\n        <p class="eyebrow">SATIN ALMA TALEP AKIŞI</p>\n        <h3>Operasyonel ihtiyaçları kontrollü talep akışına taşıyın</h3>\n        <p>Ürün/hizmet adı, tedarikçi, miktar, birim fiyat, ihtiyaç tarihi ve iş gerekçesi ile satın alma taleplerini daha yapılandırılmış hale getirin. Böylece operasyonel ihtiyaçlar karar kalitesini bozmadan ilerler.</p>\n        <a href="kurumsal-bilgi-bankasi-ve-onboarding.html" style="color: var(--cyan); font-weight: 800; display: inline-block; margin-top: 10px;">Politika ve İş Akışlarını İncele →</a>\n      </div>\n      <div class="showcase-media">\n        <img src="./assets/screenshots/phase4/tr/purchase-request-modal.webp" alt="CADRO yeni satın alma talebi modal ekranı" class="product-shot" loading="lazy" />\n      </div>\n    </article>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll">\n  <div class="section-head narrow">\n    <p class="eyebrow">İÇ LİNK YAPISI</p>\n    <h2>Masraf ve satın alma yönetimi, diğer operasyonlarla birlikte güçlenir</h2>\n  </div>\n  <div class="card-grid" style="grid-template-columns: repeat(3, minmax(0, 1fr));">\n    <article class="feature-card">\n      <h3>Puantaj ve Payroll Görünürlüğü</h3>\n      <p>Masraf, ödeme ve payroll etkilerini devam ve zaman verisi ile daha net ilişkilendirin.</p>\n      <a href="puantaj-ve-vardiya-yazilimi.html" style="color: var(--cyan); font-weight: 800;">Puantaj Modülünü İncele →</a>\n    </article>\n    <article class="feature-card">\n      <h3>Kurumsal Talep Formları</h3>\n      <p>Satın alma, İK ve operasyon taleplerini aynı workflow mantığında yöneterek süreçleri standardize edin.</p>\n      <a href="index.html#solutions" style="color: var(--cyan); font-weight: 800;">Tüm Çözümleri Gör →</a>\n    </article>\n    <article class="feature-card">\n      <h3>Zimmet ve Envanter Yönetimi</h3>\n      <p>Satın alınan ekipmanları varlık, zimmet ve teslim süreçlerine daha düzenli şekilde taşıyın.</p>\n      <a href="ik-yazilimi.html" style="color: var(--cyan); font-weight: 800;">İKYS Yapısını İncele →</a>\n    </article>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll" style="background: #f8fafc; padding: 60px 20px;">\n  <div class="section-head narrow">\n    <p class="eyebrow">MERAK EDİLENLER</p>\n    <h2>Sıkça Sorulan Sorular</h2>\n  </div>\n  <div class="seo-faq">\n    <details>\n      <summary>CADRO masraf yönetimi hangi süreçleri tek yapıda toplar?</summary>\n      <p>Çalışan masraf kayıtları, fiş ve fatura yükleme, kategori bazlı takip, onay akışları ve satın alma talepleri tek merkezde yönetilebilir.</p>\n    </details>\n    <details>\n      <summary>Satın alma ve masraf süreçleri neden aynı yapıda yönetilmeli?</summary>\n      <p>Çünkü harcama görünürlüğü, talep gerekçesi ve onay zinciri aynı operasyonel karar akışının parçasıdır. Bu yapı finans ve operasyon ekipleri için daha net kontrol sağlar.</p>\n    </details>\n    <details>\n      <summary>CADRO finans ekiplerine nasıl destek olur?</summary>\n      <p>Bekleyen, onaylanan ve reddedilen talepleri görünür kılar; fiş ve fatura takibini standardize eder ve bütçe disiplini için daha denetlenebilir bir süreç sunar.</p>\n    </details>\n  </div>\n</section>\n\n<section class="section final-cta reveal-on-scroll">\n  <div class="contact-card">\n    <div>\n      <p class="eyebrow">HAZIR MISINIZ?</p>\n      <h2>Masraf ve satın alma süreçlerinizi bugün merkezileştirin.</h2>\n      <p>CADRO ile harcama, onay ve satın alma akışlarını tek platformda yönetin.</p>\n    </div>\n    <div class="contact-actions">\n      <a class="primary-button" href="pricing.html" data-i18n-key="btn_view_plans"></a>\n      <a class="ghost-button" href="mailto:info@cadro.io">Satış Ekibine Ulaş</a>\n    </div>\n  </div>\n</section>\n    `,"performans-degerlendirme-okr":`<section class="hero reveal-on-scroll is-visible" style="padding-top: 60px;">\n  <div class="hero-copy">\n    <p class="eyebrow">PERFORMANS VE OKR YÖNETİMİ</p>\n    <h1>Hedefleri, geri bildirimi ve <br><span>gelişim görünürlüğünü tek sistemde yönetin.</span></h1>\n    <p class="hero-text">Performans yönetimi yazılımı ile 360 derece geri bildirim, OKR takibi ve performans değerlendirmeyi aynı yapı içinde yönetin. CADRO ile ekipler hedeflerini daha net görür, yöneticiler daha sağlıklı karar alır ve çalışan bağlılığı artar.</p>\n     <div class="hero-actions">\n       <a class="primary-button" href="pay.html?plan=scale&billing=monthly">Enterprise Planı İncele</a>\n       <a class="ghost-button" href="#ozellikler">Modülü Keşfet</a>\n    </div>\n  </div>\n  <div class="hero-panel">\n    <figure class="hero-screenshot">\n      <img src="./assets/screenshots/phase3/tr/performance.webp" alt="CADRO performans yönetimi ve OKR ekranı" class="product-shot" loading="eager" fetchpriority="high" style="border-radius: 12px; box-shadow: 0 20px 40px rgba(0,0,0,0.1);" />\n    </figure>\n  </div>\n</section>\n\n<section class="strip reveal-on-scroll" style="margin-top: 40px;">\n  <div>\n    <span class="strip-label">Problem</span>\n    <p>Hedeflerin görünmez kalması, geri bildirimin dağınık ilerlemesi ve değerlendirmelerin yıl sonuna sıkışması.</p>\n  </div>\n  <div>\n    <span class="strip-label">CADRO Çözümü</span>\n    <p>OKR, 360 değerlendirme ve yönetsel puanlamayı aynı akışta buluşturan merkezi performans yapısı.</p>\n  </div>\n  <div>\n    <span class="strip-label">Sonuç</span>\n    <p>Daha net hedefler, daha güçlü gelişim görünürlüğü ve karar kalitesini artıran performans verisi.</p>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll" id="ozellikler">\n  <div class="section-head narrow">\n    <p class="eyebrow">PERFORMANS MODÜLÜ</p>\n    <h2>OKR'dan 360° değerlendirmeye, AI analizine tam döngü</h2>\n  </div>\n  <div class="card-grid" style="grid-template-columns: repeat(3, minmax(0, 1fr));">\n    <article class="feature-card">\n      <h3>OKR Hedef Yönetimi</h3>\n      <p>Şirket, takım ve birey düzeyinde başlık, açıklama ve son tarih ile hedef tanımlayın. İlerleme 0–100% bandında takip edilir; durum TODO / IN_PROGRESS / COMPLETED olarak görünür.</p>\n    </article>\n    <article class="feature-card">\n      <h3>360° Değerlendirme</h3>\n      <p>Yönetici, eş, öz değerlendirme ve ast olmak üzere 4 farklı kaynaktan puan toplanır (1–5 yıldız). Her dönem için yorum ve genel karar aynı kart üzerinde birikir.</p>\n    </article>\n    <article class="feature-card">\n      <h3>AI Yetenek Analizi</h3>\n      <p>Toplanan değerlendirme verileri Gemini AI'a gönderilir. Sistem çalışanın güçlü yönlerini, gelişim alanlarını ve kariyer potansiyelini otomatik özetler.</p>\n    </article>\n    <article class="feature-card">\n      <h3>Dönem Bazlı Raporlama</h3>\n      <p>Her değerlendirme dönemi (orn. "2025 Yıl Sonu") ayrı kapatılır ve arşivlenir. Tarihçeli karşılaştırma ile çalışanın gelişim eğrisi görünür olur.</p>\n    </article>\n    <article class="feature-card">\n      <h3>Çalışan Seçimi & Karşılaştırma</h3>\n      <p>Yönetici farklı çalışanların performans profillerini yan yana inceleyebilir. Terfi ve gelişim kararları veri odaklı alınır.</p>\n    </article>\n    <article class="feature-card">\n      <h3>Kariyer & Terfi Planlaması</h3>\n      <p>Skor ve yorum verileri kariyer adilığı analizine taşınır. Yüksek potansiyel profiller ve risk altındaki yetenekler erken tespit edilir.</p>\n    </article>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll">\n  <div class="showcase-stack">\n    <article class="showcase-row">\n      <div class="showcase-copy">\n        <p class="eyebrow">YÖNETİM GÖRÜNÜRLÜİÜ</p>\n        <h3>Performans verisini karar destek katmanına taşıyın</h3>\n        <p>AI destekli değerlendirme görünümü ve karar önerileri ile performans yönetimini yalnızca ölçüm değil, aynı zamanda yönetsel içgörü kaynağı haline getirin.</p>\n        <a href="ik-yazilimi.html" style="color: var(--cyan); font-weight: 800; display: inline-block; margin-top: 10px;">Tüm İKYS Yapısını Gör →</a>\n      </div>\n      <div class="showcase-media">\n        <img src="./assets/screenshots/phase3/tr/performance-detail.webp" alt="CADRO AI destekli performans ve yetenek analizi ekranı" class="product-shot" loading="lazy" />\n      </div>\n    </article>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll">\n  <div class="section-head narrow">\n    <p class="eyebrow">İÇ LİNK YAPISI</p>\n    <h2>Performans yönetimi, diğer operasyonlarla birlikte güçlenir</h2>\n  </div>\n  <div class="card-grid" style="grid-template-columns: repeat(3, minmax(0, 1fr));">\n    <article class="feature-card">\n      <h3>Aday Takip Sistemi (ATS)</h3>\n      <p>İşe alım sonrası çalışanları gelişim ve performans yapısına daha hızlı dahil edin.</p>\n      <a href="ats-ise-alim-yazilimi.html" style="color: var(--cyan); font-weight: 800;">ATS Modülünü İncele →</a>\n    </article>\n    <article class="feature-card">\n      <h3>Dijital Özlük ve İzin Yönetimi</h3>\n      <p>Çalışan verisi ve operasyonel süreçler ile performans verisini daha tutarlı biçimde yönetin.</p>\n      <a href="dijital-ozluk-ve-izin.html" style="color: var(--cyan); font-weight: 800;">Özlük Modülünü İncele →</a>\n    </article>\n    <article class="feature-card">\n      <h3>Puantaj ve Vardiya Yönetimi</h3>\n      <p>Zaman, devam ve ekip performansı arasındaki operasyonel resmi daha net görün.</p>\n      <a href="puantaj-ve-vardiya-yazilimi.html" style="color: var(--cyan); font-weight: 800;">Puantaj Modülünü İncele →</a>\n    </article>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll" style="background: #f8fafc; padding: 60px 20px;">\n  <div class="section-head narrow">\n    <p class="eyebrow">MERAK EDİLENLER</p>\n    <h2>Sıkça Sorulan Sorular</h2>\n  </div>\n  <div class="seo-faq">\n    <details>\n      <summary>CADRO ile performans değerlendirme süreci nasıl yönetilir?</summary>\n      <p>Hedefler, geri bildirimler ve yönetici değerlendirmeleri aynı sistem içinde ilerler. Böylece performans görüşmeleri daha hazırlıklı ve daha görünür hale gelir.</p>\n    </details>\n    <details>\n      <summary>OKR ile 360 geri bildirim aynı yapıda kullanılabilir mi?</summary>\n      <p>Evet. CADRO, stratejik hedef takibi ile gelişim odaklı geri bildirim akışını aynı platform içinde bir araya getirir.</p>\n    </details>\n    <details>\n      <summary>Bu modül yalnızca İK için mi tasarlanmıştır?</summary>\n      <p>Hayır. İK, yöneticiler ve üst yönetim performans verisini farklı görünürlük seviyelerinde kullanabilir.</p>\n    </details>\n  </div>\n</section>\n\n<section class="section final-cta reveal-on-scroll">\n  <div class="contact-card">\n    <div>\n      <p class="eyebrow">HAZIR MISINIZ?</p>\n      <h2>Performans kültürünüzü daha görünür ve ölçülebilir hale getirin.</h2>\n      <p>CADRO ile hedef, geri bildirim ve yetenek yönetimini tek akışta buluşturun.</p>\n    </div>\n    <div class="contact-actions">\n      <a class="primary-button" href="pricing.html" data-i18n-key="btn_view_plans"></a>\n      <a class="ghost-button" href="mailto:info@cadro.io">Satış Ekibine Ulaş</a>\n    </div>\n  </div>\n</section>\n    `,"puantaj-ve-vardiya-yazilimi":`<section class="hero reveal-on-scroll is-visible" style="padding-top: 60px;">\n  <div class="hero-copy">\n    <p class="eyebrow">devam takibi YÖNETİMİ</p>\n    <h1>Puantajı, vardiyayı ve <br><span>mesai görünürlüğünü tek sistemde yönetin.</span></h1>\n    <p class="hero-text">Puantaj ve vardiya yazılımı ile giriş çıkış verilerini, vardiya planlarını, istisnaları ve payroll-ready raporları aynı yapı içinde toplayın. CADRO ile İK ve operasyon ekipleri zamana dayalı süreçleri daha görünür, daha kontrollü ve daha ölçülebilir hale getirir.</p>\n     <div class="hero-actions">\n       <a class="primary-button" href="pay.html?plan=growth&billing=monthly">Pro Planı İncele</a>\n       <a class="ghost-button" href="#ozellikler">Modülü Keşfet</a>\n    </div>\n  </div>\n  <div class="hero-panel">\n    <figure class="hero-screenshot">\n      <img src="./assets/screenshots/phase4/tr/devam.webp" alt="CADRO puantaj ve vardiya yönetimi ana ekranı" class="product-shot" loading="eager" fetchpriority="high" style="border-radius: 12px; box-shadow: 0 20px 40px rgba(0,0,0,0.1);" />\n    </figure>\n  </div>\n</section>\n\n<section class="strip reveal-on-scroll" style="margin-top: 40px;">\n  <div>\n    <span class="strip-label">Problem</span>\n    <p>Dağınık puantaj kayıtları, manuel vardiya takibi ve bordroya geç yansıyan istisnalar zaman operasyonlarında görünürlük kaybı yaratır.</p>\n  </div>\n  <div>\n    <span class="strip-label">CADRO Çözümü</span>\n    <p>devam, work schedules, department assignments, override yapıları ve payroll raporlarını tek akışta birleştiren merkezi yapı.</p>\n  </div>\n  <div>\n    <span class="strip-label">Sonuç</span>\n    <p>Daha temiz zaman verisi, daha güçlü vardiya disiplini ve bordro öncesi daha hızlı karar alma zemini.</p>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll" id="ozellikler">\n  <div class="section-head narrow">\n    <p class="eyebrow">MODÜL ÖZELLİKLERİ</p>\n    <h2>Zaman ve devam yönetimini standartlaştırın</h2>\n  </div>\n  <div class="card-grid" style="grid-template-columns: repeat(3, minmax(0, 1fr));">\n    <article class="feature-card">\n      <h3>Puantaj ve Devam Takibi</h3>\n      <p>Çalışan giriş çıkışlarını, günlük durumları ve istisnaları tek görünümde izleyin. Geç kalma, erken çıkış ve mesai sinyalleri daha hızlı fark edilsin.</p>\n    </article>\n    <article class="feature-card">\n      <h3>Vardiya ve Departman Kuralları</h3>\n      <p>Departman bazlı vardiya varsayımları tanımlayın, çalışan bazlı override yapıları kurun ve operasyonel farklılıkları kontrollü biçimde yönetin.</p>\n    </article>\n    <article class="feature-card">\n      <h3>Payroll-Ready Raporlama</h3>\n      <p>Çalışma günü, fazla mesai, geç kalma ve izin etkilerini raporlayarak bordro sürecine daha temiz ve daha denetlenebilir veri aktarın.</p>\n    </article>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll">\n  <div class="showcase-stack">\n    <article class="showcase-row">\n      <div class="showcase-copy">\n        <p class="eyebrow">PAYROLL GÖRÜNÜRLÜİÜ</p>\n        <h3>Bordro öncesi tabloyu daha net görün</h3>\n        <p>Onaylanmış izinler, tam ücretli sağlık raporları, eksik günler ve fazla mesai etkileri aynı rapor katmanında toplanır. Böylece İK ve finans ekipleri son dakika sürprizleri yerine kontrollü veri ile çalışır.</p>\n        <a href="masraf-ve-satin-alma.html" style="color: var(--cyan); font-weight: 800; display: inline-block; margin-top: 10px;">Masraf ve Satın Alma Modülünü İncele →</a>\n      </div>\n      <div class="showcase-media">\n        <img src="./assets/screenshots/phase4/tr/devam-payroll.webp" alt="CADRO puantaj payroll raporu ekranı" class="product-shot" loading="lazy" />\n      </div>\n    </article>\n    <article class="showcase-row">\n      <div class="showcase-copy">\n        <p class="eyebrow">İSTİSNA YÖNETİMİ</p>\n        <h3>Sağlık raporu ve özel durum akışlarını tek yapıdan yönetin</h3>\n        <p>İstisnai sağlık raporları ve özel devamsızlık kayıtları aynı devam sürecine entegre edilir. Böylece operasyonel gerçeklik ile bordro mantığı birbirinden kopmaz.</p>\n        <a href="dijital-ozluk-ve-izin.html" style="color: var(--cyan); font-weight: 800; display: inline-block; margin-top: 10px;">Dijital Özlük ve İzin Modülüne Göz At →</a>\n      </div>\n      <div class="showcase-media">\n        <img src="./assets/screenshots/phase4/tr/devam-health.webp" alt="CADRO sağlık raporu giriş ekranı" class="product-shot" loading="lazy" />\n      </div>\n    </article>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll">\n  <div class="section-head narrow">\n    <p class="eyebrow">İÇ LİNK YAPISI</p>\n    <h2>Puantaj yönetimi, diğer İK operasyonlarıyla birlikte güçlenir</h2>\n  </div>\n  <div class="card-grid" style="grid-template-columns: repeat(3, minmax(0, 1fr));">\n    <article class="feature-card">\n      <h3>Dijital Özlük ve İzin Yönetimi</h3>\n      <p>İzin, evrak ve çalışan kayıtları ile devam verisini daha tutarlı biçimde yönetin.</p>\n      <a href="dijital-ozluk-ve-izin.html" style="color: var(--cyan); font-weight: 800;">Özlük ve İzin Modülünü İncele →</a>\n    </article>\n    <article class="feature-card">\n      <h3>Masraf ve Satın Alma Yönetimi</h3>\n      <p>Payroll ve operasyon verisini masraf, onay ve satın alma süreçleriyle daha güçlü bağlayın.</p>\n      <a href="masraf-ve-satin-alma.html" style="color: var(--cyan); font-weight: 800;">Masraf Modülünü İncele →</a>\n    </article>\n    <article class="feature-card">\n      <h3>Performans ve OKR</h3>\n      <p>Devamlılık ve operasyonel düzeni performans ve hedef yönetimi ile birlikte değerlendirin.</p>\n      <a href="performans-degerlendirme-okr.html" style="color: var(--cyan); font-weight: 800;">Performans Modülünü İncele →</a>\n    </article>\n  </div>\n</section>\n\n<section class="section reveal-on-scroll" style="background: #f8fafc; padding: 60px 20px;">\n  <div class="section-head narrow">\n    <p class="eyebrow">MERAK EDİLENLER</p>\n    <h2>Sıkça Sorulan Sorular</h2>\n  </div>\n  <div class="seo-faq">\n    <details>\n      <summary>CADRO puantaj sistemi hangi verileri tek yerde toplar?</summary>\n      <p>Giriş çıkış saatleri, vardiya kuralları, geç kalma, erken çıkış, fazla mesai ve bordroya hazır özetler tek merkezde görüntülenebilir.</p>\n    </details>\n    <details>\n      <summary>Vardiya ve departman bazlı farklı kurallar tanımlanabilir mi?</summary>\n      <p>Evet. Departman bazlı vardiya şablonları, çalışan bazlı override yapıları ve payroll raporları aynı sistem içinde yönetilebilir.</p>\n    </details>\n    <details>\n      <summary>CADRO puantaj modülü bordro sürecini nasıl destekler?</summary>\n      <p>Zaman kayıtlarını standartlaştırır, eksik ve istisna durumlarını görünür kılar ve payroll-ready raporlarla muhasebe ve İK ekiplerinin işini kolaylaştırır.</p>\n    </details>\n  </div>\n</section>\n\n<section class="section final-cta reveal-on-scroll">\n  <div class="contact-card">\n    <div>\n      <p class="eyebrow">HAZIR MISINIZ?</p>\n      <h2>Zaman ve devam süreçlerinizi bugün daha görünür hale getirin.</h2>\n      <p>CADRO ile puantaj, vardiya ve payroll görünürlüğünü tek platformda yönetin.</p>\n    </div>\n    <div class="contact-actions">\n      <a class="primary-button" href="pricing.html" data-i18n-key="btn_view_plans"></a>\n      <a class="ghost-button" href="mailto:info@cadro.io">Satış Ekibine Ulaş</a>\n    </div>\n  </div>\n</section>\n  `,"ucretsiz-sablonlar":`<section class="hero reveal-on-scroll is-visible" style="padding-top: 60px;">\n  <div class="container">\n    <div class="hero__content">\n      <div class="eyebrow">ÜCRETSİZ KAYNAKLAR</div>\n      <h1>Ücretsiz İK Şablonları</h1>\n      <p>İşe alım, işe giriş, performans ve belge süreçlerini hızlandıracak hazır şablonları inceleyin.</p>\n      <a href="/pricing" class="btn btn-primary">Fiyatları İncele</a>\n    </div>\n  </div>\n</section>\n\n<section class="section">\n  <div class="container">\n    <div class="grid-2">\n      <div>\n        <h2>Hazır Kullanılabilir Şablonlar</h2>\n        <p>Politika, işe giriş ve performans şablonlarını indirip dakikalar içinde kendi yapınıza uyarlayın.</p>\n      </div>\n      <div>\n        <ul class="feature-list">\n          <li>Politika ve çalışan el kitabı şablonları</li>\n          <li>Onboarding kontrol listeleri</li>\n          <li>Performans değerlendirme formları</li>\n          <li>Uyum ve denetim dokümanları</li>\n        </ul>\n      </div>\n    </div>\n  </div>\n</section>\n\n<section class="section alt">\n  <div class="container">\n    <div class="grid-3">\n      <div class="card">\n        <h3>İK Politika Paketi</h3>\n        <p>Düzenlenebilir bölümler ve iyi uygulama örnekleri içeren temel İK politika seti.</p>\n      </div>\n      <div class="card">\n        <h3>Onboarding Kiti</h3>\n        <p>Hoş geldin e-postaları, kontrol listeleri ve eğitim zaman planı örnekleri.</p>\n      </div>\n      <div class="card">\n        <h3>Değerlendirme Şablonları</h3>\n        <p>Çeyreklik ve yıllık performans görüşmeleri için hazır form setleri.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<section class="section">\n  <div class="container" style="text-align:center;">\n    <a href="/contact" class="btn btn-primary">Şablonları Talep Et</a>\n  </div>\n</section>\n  `,"vaka-calismalari":`\n<section class="case-hero">\n  <div class="case-shell">\n    <div class="industry">VAKA ÇALIŞMALARI</div>\n    <h1>İK Yazılımı Vaka Çalışmaları ve Kullanım Senaryoları</h1>\n    <p>CADRO’nun farklı sektörlerde işe alım, puantaj, dijital özlük dosyası, performans yönetimi ve kurumsal gelişim süreçlerini nasıl daha görünür ve daha kontrollü hale getirdiğini örnek kullanım senaryoları üzerinden inceleyin.</p>\n  </div>\n</section>\n<section class="section-pad">\n  <div class="case-shell">\n    <div class="cta-panel">\n      <h2>Büyük ölçekli organizasyonlarda tek platform görünürlüğü</h2>\n      <p>Üretim, lojistik, perakende ve bilgi yoğun organizasyonlarda çalışan yönetimi, vardiya, izin, belge ve iç talep akışlarını tek platformda toplamak operasyon kalitesini güçlendirir.</p>\n      <a class="primary-button" href="vaka-calismasi-uretim-devi.html">Üretim vaka çalışmasını oku</a>\n    </div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:10px;">\n  <div class="case-shell">\n    <div class="section-head narrow" style="margin-bottom:22px;">\n      <p class="eyebrow">CADRO</p>\n      <h2>Sektör bazlı kullanım senaryoları</h2>\n      <p>Her kullanım senaryosu, CADRO’nun farklı operasyonel ihtiyaçlara nasıl uyum sağladığını gösterir.</p>\n    </div>\n    <div class="hub-grid"><a class="hub-card" href="vaka-calismasi-tech-startup.html"><span class="badge">Teknoloji Girişimi</span><h3>Teknoloji Girişimi</h3><p>İşe alım, işe giriş ve performans görünürlüğü ile büyüme dönemindeki İK operasyonlarını standartlaştırın.</p></a><a class="hub-card" href="vaka-calismasi-perakende.html"><span class="badge">Perakende</span><h3>Perakende</h3><p>Çok lokasyonlu puantaj, vardiya ve izin süreçlerini daha kontrollü yönetin.</p></a><a class="hub-card" href="vaka-calismasi-saglik.html"><span class="badge">Sağlık</span><h3>Sağlık</h3><p>Dijital özlük dosyası ve uyum süreçlerinde görünürlüğü güçlendirin.</p></a><a class="hub-card" href="vaka-calismasi-danismanlik.html"><span class="badge">Danışmanlık</span><h3>Danışmanlık</h3><p>Performans, hedef ve yetenek görünürlüğünü daha stratejik yönetin.</p></a><a class="hub-card" href="vaka-calismasi-egitim.html"><span class="badge">Eğitim</span><h3>Eğitim</h3><p>Kurumsal eğitim ve çalışan gelişimi süreçlerini daha ölçülebilir hale getirin.</p></a><a class="hub-card" href="vaka-calismasi-lojistik.html"><span class="badge">Lojistik</span><h3>Lojistik</h3><p>Saha ekiplerinde lokasyon bazlı puantaj ve iş gücü görünürlüğünü güçlendirin.</p></a><a class="hub-card" href="vaka-calismasi-uretim-devi.html"><span class="badge">Üretim</span><h3>Üretim</h3><p>Büyük operasyonlarda süreçleri tek bir İK yazılımı yapısında birleştirin.</p></a></div>\n  </div>\n</section>\n\n`,"vaka-calismasi-tech-startup":`\n<section class="case-hero">\n  <div class="case-shell">\n    <div class="case-breadcrumbs"><span>Ana Sayfa / Vaka Çalışmaları / Tech Startup</span></div>\n    <div class="case-hero-grid">\n      <div>\n        <div class="industry">TEKNOLOJİ / SAAS</div>\n        <h1>Tech Startup: İK yazılımı ile Büyüme Döneminde İK Süreçlerini Standartlaştırmak</h1>\n        <p>Hızlı büyüyen teknoloji şirketlerinde İK süreçleri, ekip sayısı arttıkça daha karmaşık hale gelir. Bu vaka çalışması, CADRO İKYS’in işe alım, işe giriş, çalışan yönetimi ve performans süreçlerini tek merkezde toplayarak büyüme dönemindeki İK operasyonlarını nasıl daha kontrollü hale getirdiğini anlatır.</p>\n      </div>\n      <div class="case-shot"><img src="./assets/screenshots/phase3/tr/ats.webp" alt="CADRO TEKNOLOJİ / SAAS İK yazılımı ekran görüntüsü" loading="eager"/></div>\n    </div>\n  </div>\n</section>\n<section class="section-pad">\n  <div class="case-shell two-col">\n    <div class="section-box">\n      <h2>Zorluk</h2>\n      <ul><li>İşe alım süreci farklı araçlar arasında bölündüğü için aday görünürlüğü ve karar hızı zayıflıyordu.</li><li>işe giriş adımları standart olmadığı için yeni çalışan deneyimi ekipten ekibe değişiyordu.</li><li>Çalışan verisi ve performans görünürlüğü büyüme hızına paralel ilerlemiyordu.</li></ul>\n    </div>\n    <div class="section-box">\n      <h2>CADRO yaklaşımı</h2>\n      <ul><li>ATS, işe giriş, çalışan yönetimi ve performans süreçleri tek İK yazılımı platformunda birleştirildi.</li><li>işe alım akışı, görev akışları ve çalışan kayıtları daha görünür ve daha standart hale getirildi.</li><li>Yöneticiler ve İK ekipleri, aynı operasyon verisi üzerinden daha hızlı karar alabilir hale geldi.</li></ul>\n    </div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:0;">\n  <div class="case-shell">\n    <div class="result-panel">\n      <h2>Sonuç</h2>\n      <p>Daha görünür işe alım süreçleri, daha düzenli işe giriş akışları ve daha net çalışan verisi yönetimi sayesinde şirket, büyüme dönemini daha kontrollü bir İK yapısıyla destekleyebildi. Sonuç yalnızca operasyonel kolaylık değil, aynı zamanda daha rafine bir çalışan deneyimi oldu.</p>\n    </div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:16px;">\n  <div class="case-shell">\n    <div class="section-head narrow" style="margin-bottom:22px;">\n      <p class="eyebrow">FAQ</p>\n      <h2>Sık Sorulan Sorular</h2>\n    </div>\n    <div class="faq-wrap"><div class="faq-card"><h3>Tech startup’lar için en kritik HR yazılım modülleri nelerdir?</h3><p>Hızlı büyüyen ekiplerde ATS, işe giriş, çalışan yönetimi ve performans yönetimi modülleri en kritik yapı taşlarıdır.</p></div><div class="faq-card"><h3>bulut tabanlı İK yazılımı büyüme döneminde hangi süreçleri standartlaştırır?</h3><p>İşe alım, işe giriş, çalışan kayıtları, izin, performans ve yönetici görünürlüğü gibi süreçleri tek yapıda standardize eder.</p></div><div class="faq-card"><h3>CADRO İKYS işe alım ve işe giriş süreçlerini nasıl destekler?</h3><p>Aday takibini, teklif aşamalarını ve yeni çalışan görev akışlarını birbirine bağlayarak daha düzenli bir employee lifecycle sağlar.</p></div></div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:20px;">\n  <div class="case-shell">\n    <div class="section-head narrow" style="margin-bottom:22px;">\n      <p class="eyebrow">CADRO HRMS</p>\n      <h2>İlgili sayfalar</h2>\n    </div>\n    <div class="related-grid"><a class="related-card" href="ats-ise-alim-yazilimi.html"><strong>ATS yazılımını incele</strong><span>Aday takip sistemi ve işe alım akışı yapısını keşfedin.</span></a><a class="related-card" href="kurumsal-bilgi-bankasi-ve-onboarding.html"><strong>işe giriş akışını incele</strong><span>Yeni çalışan başlangıçlarını kontrol listesi ve süreç görünürlüğü ile yönetin.</span></a><a class="related-card" href="performans-degerlendirme-okr.html"><strong>Performans modülünü incele</strong><span>Hedef, geri bildirim ve performans görünürlüğünü tek yapıda yönetin.</span></a></div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:18px;">\n  <div class="case-shell">\n    <div class="cta-panel">\n      <h2>İK yazılımı ile büyüme dönemini daha kontrollü yönetin</h2>\n      <p>CADRO İKYS, hızlı büyüyen ekipler için işe alım, işe giriş ve çalışan süreçlerini tek bulut platformunda birleştirir.</p>\n      <a class="primary-button" href="ik-yazilimi.html">CADRO HRMS</a>\n    </div>\n  </div>\n</section>\n\n`,"vaka-calismasi-perakende":`\n<section class="case-hero">\n  <div class="case-shell">\n    <div class="case-breadcrumbs"><span>Ana Sayfa / Vaka Çalışmaları / Perakende</span></div>\n    <div class="case-hero-grid">\n      <div>\n        <div class="industry">PERAKENDE</div>\n        <h1>Perakende: Puantaj, Lokasyon ve İzin Süreçlerini Daha Kontrollü Yönetmek</h1>\n        <p>Perakende sektöründe çok lokasyonlu yapı, zaman ve devam yönetimini daha hassas hale getirir. Bu vaka çalışması, CADRO İKYS ile puantaj, lokasyon doğrulaması ve izin onay süreçlerinin nasıl daha görünür hale geldiğini gösterir.</p>\n      </div>\n      <div class="case-shot"><img src="./assets/screenshots/phase4/tr/devam.webp" alt="CADRO PERAKENDE İK yazılımı ekran görüntüsü" loading="eager"/></div>\n    </div>\n  </div>\n</section>\n<section class="section-pad">\n  <div class="case-shell two-col">\n    <div class="section-box">\n      <h2>Zorluk</h2>\n      <ul><li>Şubeler arasında puantaj ve vardiya takibi farklı alışkanlıklarla yürüyordu.</li><li>Lokasyon bazlı giriş-çıkış doğrulama ve izin onay akışı yeterince görünür değildi.</li><li>İK ve operasyon ekipleri manuel takip nedeniyle zaman kaybediyordu.</li></ul>\n    </div>\n    <div class="section-box">\n      <h2>CADRO yaklaşımı</h2>\n      <ul><li>devam takibi, izin yönetimi ve lokasyon kuralları tek İKYS yapısında toplandı.</li><li>Çalışma planları, devam kayıtları ve izin talepleri daha merkezi bir akışla yönetildi.</li><li>Yöneticiler şube bazlı görünürlük kazanırken İK ekipleri daha standart bir operasyon modeli oluşturdu.</li></ul>\n    </div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:0;">\n  <div class="case-shell">\n    <div class="result-panel">\n      <h2>Sonuç</h2>\n      <p>Daha standart puantaj yapısı, daha net izin onay akışları ve daha güçlü lokasyon doğrulaması sayesinde çok şubeli perakende operasyonları daha kontrollü hale geldi. Sonuç, daha yüksek görünürlük ve daha düşük manuel takip yükü oldu.</p>\n    </div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:16px;">\n  <div class="case-shell">\n    <div class="section-head narrow" style="margin-bottom:22px;">\n      <p class="eyebrow">FAQ</p>\n      <h2>Sık Sorulan Sorular</h2>\n    </div>\n    <div class="faq-wrap"><div class="faq-card"><h3>Perakende için time and devam software neden önemlidir?</h3><p>Çok lokasyonlu yapılarda şube bazlı devam görünürlüğü ve vardiya disiplini sağlamak için önemlidir.</p></div><div class="faq-card"><h3>İzin yönetimi ile puantaj sistemi birlikte çalışabilir mi?</h3><p>Evet, izin yönetimi ve devam verileri aynı İKYS içinde birlikte yönetildiğinde operasyonel netlik artar.</p></div><div class="faq-card"><h3>Lokasyon doğrulaması perakende operasyonlarına ne kazandırır?</h3><p>Doğru şubeden doğru kayıt alınmasını destekler ve daha güvenilir iş gücü verisi üretir.</p></div></div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:20px;">\n  <div class="case-shell">\n    <div class="section-head narrow" style="margin-bottom:22px;">\n      <p class="eyebrow">CADRO HRMS</p>\n      <h2>İlgili sayfalar</h2>\n    </div>\n    <div class="related-grid"><a class="related-card" href="puantaj-ve-vardiya-yazilimi.html"><strong>Puantaj yazılımını incele</strong><span>devam, vardiya ve mesai süreçlerini tek yapıda yönetin.</span></a><a class="related-card" href="dijital-ozluk-ve-izin.html"><strong>İzin yönetimini incele</strong><span>İzin talepleri, kalan hak edişler ve onay akışlarını görünür kılın.</span></a><a class="related-card" href="ik-yazilimi.html"><strong>İKYS yaklaşımını incele</strong><span>Bulut tabanlı HR yazılımı ile perakende operasyonlarını merkezileştirin.</span></a></div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:18px;">\n  <div class="case-shell">\n    <div class="cta-panel">\n      <h2>Perakende ekipleri için daha görünür iş gücü yönetimi</h2>\n      <p>CADRO İKYS; devam, leave ve çalışan operasyonlarını tek bulut platformunda toplar.</p>\n      <a class="primary-button" href="ik-yazilimi.html">CADRO HRMS</a>\n    </div>\n  </div>\n</section>\n\n`,"vaka-calismasi-saglik":`\n<section class="case-hero">\n  <div class="case-shell">\n    <div class="case-breadcrumbs"><span>Ana Sayfa / Vaka Çalışmaları / Sağlık</span></div>\n    <div class="case-hero-grid">\n      <div>\n        <div class="industry">SAİLIK</div>\n        <h1>Sağlık Operasyonlarında Dijital Özlük Dosyası ve Uyum Süreçlerini Güçlendirmek</h1>\n        <p>Sağlık sektöründe belge yönetimi, politika görünürlüğü ve çalışan dosyalarının güncelliği kritik önemdedir. Bu vaka çalışması, CADRO İKYS ile dijital özlük dosyası ve uyum süreçlerinin nasıl daha merkezi hale getirildiğini anlatır.</p>\n      </div>\n      <div class="case-shot"><img src="./assets/screenshots/phase3/tr/e-dossier.webp" alt="CADRO SAİLIK İK yazılımı ekran görüntüsü" loading="eager"/></div>\n    </div>\n  </div>\n</section>\n<section class="section-pad">\n  <div class="case-shell two-col">\n    <div class="section-box">\n      <h2>Zorluk</h2>\n      <ul><li>Çalışan belgeleri, onay akışları ve politika görünürlüğü dağınık sistemlerde ilerliyordu.</li><li>Eksik evrak ve geçerlilik takibi operasyonel netliği azaltıyordu.</li><li>Uyum süreçleri merkezi görünürlükten yoksun olduğu için takip yükü artıyordu.</li></ul>\n    </div>\n    <div class="section-box">\n      <h2>CADRO yaklaşımı</h2>\n      <ul><li>E-Dossier, policy management ve compliance akışları tek HR software yapısında toplandı.</li><li>Belge yükleme, geçerlilik kontrolü ve onay süreçleri daha merkezi hale getirildi.</li><li>İK ekipleri eksik evrak, güncellik ve kurumsal onay görünürlüğünü tek yerden yönetebilir hale geldi.</li></ul>\n    </div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:0;">\n  <div class="case-shell">\n    <div class="result-panel">\n      <h2>Sonuç</h2>\n      <p>Kurumsal bilgi akışında daha fazla düzen, belge süreçlerinde daha fazla görünürlük ve uyum tarafında daha güçlü operasyonel takip sağlandı. Sonuç, daha güvenilir ve daha sürdürülebilir bir İK uyumluluğu yapısı oldu.</p>\n    </div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:16px;">\n  <div class="case-shell">\n    <div class="section-head narrow" style="margin-bottom:22px;">\n      <p class="eyebrow">FAQ</p>\n      <h2>Sık Sorulan Sorular</h2>\n    </div>\n    <div class="faq-wrap"><div class="faq-card"><h3>Dijital özlük dosyası sağlık sektöründe neden önemlidir?</h3><p>Çünkü çalışan belgelerinin güncel, görünür ve izlenebilir olması sağlık operasyonlarında kritik bir uyum alanıdır.</p></div><div class="faq-card"><h3>Employee document management yazılımı hangi riskleri azaltır?</h3><p>Eksik evrak, versiyon kaybı, geçerlilik belirsizliği ve manuel takip risklerini azaltır.</p></div><div class="faq-card"><h3>Politika ve belge takibi İK uyumluluğu için nasıl katkı sağlar?</h3><p>Duyuruların, belge yüklemelerinin ve onay akışlarının daha kontrollü ilerlemesini sağlar.</p></div></div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:20px;">\n  <div class="case-shell">\n    <div class="section-head narrow" style="margin-bottom:22px;">\n      <p class="eyebrow">CADRO HRMS</p>\n      <h2>İlgili sayfalar</h2>\n    </div>\n    <div class="related-grid"><a class="related-card" href="dijital-ozluk-ve-izin.html"><strong>Dijital özlük modülünü incele</strong><span>Çalışan belgeleri, izin süreçleri ve özlük görünürlüğünü tek yapıda yönetin.</span></a><a class="related-card" href="kurumsal-bilgi-bankasi-ve-onboarding.html"><strong>Politika yönetimini incele</strong><span>politika onayı ve kurumsal bilgi akışını merkezileştirin.</span></a><a class="related-card" href="compliance.html"><strong>Uyumluluk sayfasını incele</strong><span>İK uyumluluğu yaklaşımını ve süreç standardizasyonunu keşfedin.</span></a></div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:18px;">\n  <div class="case-shell">\n    <div class="cta-panel">\n      <h2>İK uyumluluğu süreçlerini daha görünür yönetin</h2>\n      <p>CADRO İKYS ile belge, politika ve çalışan dosyası süreçlerini bulut tabanlı tek bir HR platformunda birleştirin.</p>\n      <a class="primary-button" href="ik-yazilimi.html">CADRO HRMS</a>\n    </div>\n  </div>\n</section>\n\n`,"vaka-calismasi-danismanlik":`\n<section class="case-hero">\n  <div class="case-shell">\n    <div class="case-breadcrumbs"><span>Ana Sayfa / Vaka Çalışmaları / Danışmanlık</span></div>\n    <div class="case-hero-grid">\n      <div>\n        <div class="industry">DANIŞMANLIK</div>\n        <h1>Danışmanlık Şirketlerinde Performans ve Yetenek Yönetimini Derinleştirmek</h1>\n        <p>Danışmanlık şirketlerinde performans görünürlüğü, çalışan gelişimi ve hedef yönetimi stratejik önem taşır. Bu vaka çalışması, CADRO İKYS ile performans yönetimi ve yetenek süreçlerinin daha ölçülebilir hale gelmesini anlatır.</p>\n      </div>\n      <div class="case-shot"><img src="./assets/screenshots/phase3/tr/performance.webp" alt="CADRO DANIŞMANLIK İK yazılımı ekran görüntüsü" loading="eager"/></div>\n    </div>\n  </div>\n</section>\n<section class="section-pad">\n  <div class="case-shell two-col">\n    <div class="section-box">\n      <h2>Zorluk</h2>\n      <ul><li>Hedef takibi, yönetsel değerlendirme ve çalışan gelişimi farklı araçlara dağılmıştı.</li><li>Geri bildirim süreçleri ile yetenek kararları arasında yeterli bağ kurulamadığı için yönetsel görünürlük zayıflıyordu.</li><li>Performans görüşmeleri daha parçalı ilerlediği için kurumsal gelişim resmi netleşmiyordu.</li></ul>\n    </div>\n    <div class="section-box">\n      <h2>CADRO yaklaşımı</h2>\n      <ul><li>OKR, 360 derece değerlendirme ve yönetsel puanlama tek performans yönetimi yapısında toplandı.</li><li>Çalışan gelişim alanları, güçlü yönler ve performans görünürlüğü daha bütüncül hale getirildi.</li><li>Yönetim ekipleri performans ve yetenek kararlarını daha net veriyle destekleyebilir oldu.</li></ul>\n    </div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:0;">\n  <div class="case-shell">\n    <div class="result-panel">\n      <h2>Sonuç</h2>\n      <p>Daha ölçülebilir hedefler, daha görünür geri bildirim akışı ve daha net gelişim alanları sayesinde performans yönetimi daha stratejik bir zemine taşındı. Sonuç, daha güçlü talent visibility ve daha rafine karar desteği oldu.</p>\n    </div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:16px;">\n  <div class="case-shell">\n    <div class="section-head narrow" style="margin-bottom:22px;">\n      <p class="eyebrow">FAQ</p>\n      <h2>Sık Sorulan Sorular</h2>\n    </div>\n    <div class="faq-wrap"><div class="faq-card"><h3>performans yönetimi software danışmanlık şirketlerinde neden kritiktir?</h3><p>Çünkü bilgi yoğun yapılarda hedef görünürlüğü, geri bildirim kalitesi ve yetenek yönetimi doğrudan operasyonel kaliteyi etkiler.</p></div><div class="faq-card"><h3>OKR ve 360 review birlikte nasıl çalışır?</h3><p>OKR hedefleri, 360 derece geri bildirim ve yönetsel puanlama birlikte kullanıldığında performans daha bütüncül ölçülür.</p></div><div class="faq-card"><h3>Talent visibility yöneticilere ne sağlar?</h3><p>Yöneticilere güçlü yönler, gelişim alanları ve potansiyel profiller hakkında daha net karar zemini sağlar.</p></div></div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:20px;">\n  <div class="case-shell">\n    <div class="section-head narrow" style="margin-bottom:22px;">\n      <p class="eyebrow">CADRO HRMS</p>\n      <h2>İlgili sayfalar</h2>\n    </div>\n    <div class="related-grid"><a class="related-card" href="performans-degerlendirme-okr.html"><strong>Performans modülünü incele</strong><span>OKR, 360 değerlendirme ve geri bildirim akışlarını tek platformda yönetin.</span></a><a class="related-card" href="blog.html"><strong>İlgili içgörüleri oku</strong><span>Performans yönetimi ve HR analytics içeriklerini inceleyin.</span></a><a class="related-card" href="faq.html"><strong>SSS sayfasını incele</strong><span>Performans, modüller ve uygulama süreçleri hakkında sık sorulan sorulara bakın.</span></a></div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:18px;">\n  <div class="case-shell">\n    <div class="cta-panel">\n      <h2>Performans yönetimini daha stratejik hale getirin</h2>\n      <p>CADRO İKYS; hedefler, geri bildirim ve yetenek görünürlüğünü tek bulut tabanlı İK yazılımı platformunda toplar.</p>\n      <a class="primary-button" href="ik-yazilimi.html">CADRO HRMS</a>\n    </div>\n  </div>\n</section>\n\n`,"vaka-calismasi-egitim":`\n<section class="case-hero">\n  <div class="case-shell">\n    <div class="case-breadcrumbs"><span>Ana Sayfa / Vaka Çalışmaları / Eğitim</span></div>\n    <div class="case-hero-grid">\n      <div>\n        <div class="industry">EİİTİM</div>\n        <h1>Kurumsal Eğitim Süreçlerini Daha Planlı ve Ölçülebilir Hale Getirmek</h1>\n        <p>Kurumsal öğrenme süreçleri, çalışan gelişimi ve şirket kültürü açısından önemli bir yapı taşıdır. Bu vaka çalışması, CADRO İKYS’in eğitim planlama, katılım ve raporlama süreçlerini nasıl daha sistemli hale getirdiğini anlatır.</p>\n      </div>\n      <div class="case-shot"><img src="./assets/screenshots/phase5/tr/onboarding.webp" alt="CADRO EİİTİM İK yazılımı ekran görüntüsü" loading="eager"/></div>\n    </div>\n  </div>\n</section>\n<section class="section-pad">\n  <div class="case-shell two-col">\n    <div class="section-box">\n      <h2>Zorluk</h2>\n      <ul><li>Eğitim planları, katılımcı takibi ve yoklama süreçleri dağınık ilerliyordu.</li><li>Kurumsal gelişim faaliyetlerinin etkisi ölçülebilir biçimde görülemiyordu.</li><li>Farklı ekipler için eğitim görünürlüğü ve raporlama standardı yeterince güçlü değildi.</li></ul>\n    </div>\n    <div class="section-box">\n      <h2>CADRO yaklaşımı</h2>\n      <ul><li>Kurumsal eğitim akışları, katılımcı yönetimi ve raporlama süreçleri tek platformda toplandı.</li><li>Eğitim planlama, devam ve çıktı görünürlüğü daha sistemli hale getirildi.</li><li>İK ekipleri çalışan gelişimini daha görünür ve daha düzenli takip edebilir oldu.</li></ul>\n    </div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:0;">\n  <div class="case-shell">\n    <div class="result-panel">\n      <h2>Sonuç</h2>\n      <p>Kurumsal gelişim faaliyetleri daha görünür, daha ölçülebilir ve daha sürdürülebilir hale geldi. Eğitim yönetimi yalnızca takvim bazlı bir planlama olmaktan çıkıp çalışan gelişimini destekleyen daha stratejik bir yapıya dönüştü.</p>\n    </div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:16px;">\n  <div class="case-shell">\n    <div class="section-head narrow" style="margin-bottom:22px;">\n      <p class="eyebrow">FAQ</p>\n      <h2>Sık Sorulan Sorular</h2>\n    </div>\n    <div class="faq-wrap"><div class="faq-card"><h3>LMS software çalışan gelişiminde nasıl kullanılır?</h3><p>Eğitim planlama, katılım takibi, yoklama ve raporlamayı merkezileştirerek kullanılır.</p></div><div class="faq-card"><h3>Eğitim takibi için İKYS kullanmak ne kazandırır?</h3><p>Kurumsal öğrenme süreçlerinde görünürlük, standartlaştırma ve daha düzenli takip sağlar.</p></div><div class="faq-card"><h3>Training devam ve reporting neden önemlidir?</h3><p>Eğitim faaliyetlerinin etkisini görmek ve gelişim yatırımlarını daha iyi yönetmek için önemlidir.</p></div></div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:20px;">\n  <div class="case-shell">\n    <div class="section-head narrow" style="margin-bottom:22px;">\n      <p class="eyebrow">CADRO HRMS</p>\n      <h2>İlgili sayfalar</h2>\n    </div>\n    <div class="related-grid"><a class="related-card" href="kurumsal-bilgi-bankasi-ve-onboarding.html"><strong>Kurumsal gelişim akışlarını incele</strong><span>işe giriş, bilgi bankası ve çalışan adaptasyon süreçlerini merkezileştirin.</span></a><a class="related-card" href="performans-degerlendirme-okr.html"><strong>Performans görünürlüğünü incele</strong><span>Gelişim ve performans süreçlerini birbiriyle uyumlu yönetin.</span></a><a class="related-card" href="blog.html"><strong>İlgili kaynakları oku</strong><span>Employee development ve İK yazılımı yaklaşımı hakkında daha fazla içerik inceleyin.</span></a></div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:18px;">\n  <div class="case-shell">\n    <div class="cta-panel">\n      <h2>Kurumsal öğrenmeyi daha görünür hale getirin</h2>\n      <p>CADRO İKYS ile eğitim, adaptasyon ve çalışan gelişimi süreçlerini tek bulut platformunda yönetin.</p>\n      <a class="primary-button" href="ik-yazilimi.html">CADRO HRMS</a>\n    </div>\n  </div>\n</section>\n\n`,"vaka-calismasi-lojistik":`\n<section class="case-hero">\n  <div class="case-shell">\n    <div class="case-breadcrumbs"><span>Ana Sayfa / Vaka Çalışmaları / Lojistik</span></div>\n    <div class="case-hero-grid">\n      <div>\n        <div class="industry">LOJİSTİK</div>\n        <h1>Lojistik Operasyonlarında Lokasyon ve Zaman Takibini Güçlendirmek</h1>\n        <p>Saha ekiplerinin yoğun olduğu lojistik operasyonlarında giriş-çıkış doğrulaması ve lokasyon bazlı takip kritik rol oynar. Bu vaka çalışması, CADRO İKYS ile lokasyon ve devam süreçlerinin nasıl dijitalleştirildiğini gösterir.</p>\n      </div>\n      <div class="case-shot"><img src="./assets/screenshots/phase4/tr/devam.webp" alt="CADRO LOJİSTİK İK yazılımı ekran görüntüsü" loading="eager"/></div>\n    </div>\n  </div>\n</section>\n<section class="section-pad">\n  <div class="case-shell two-col">\n    <div class="section-box">\n      <h2>Zorluk</h2>\n      <ul><li>Saha ekiplerinin giriş-çıkış verileri dağınık kaynaklardan toplanıyordu.</li><li>Lokasyon doğrulaması ve devam görünürlüğü merkezi biçimde izlenemiyordu.</li><li>Dağıtık operasyon yapısı nedeniyle vardiya ve saha kontrolü manuel yük oluşturuyordu.</li></ul>\n    </div>\n    <div class="section-box">\n      <h2>CADRO yaklaşımı</h2>\n      <ul><li>devam süreçleri ve lokasyon bazlı kurallar daha merkezi bir İKYS yapısında toplandı.</li><li>Giriş-çıkış verileri, saha ekipleri ve zaman yönetimi daha görünür hale getirildi.</li><li>Operasyon ve İK ekipleri, saha hareketliliğini daha kontrollü izleyebilir oldu.</li></ul>\n    </div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:0;">\n  <div class="case-shell">\n    <div class="result-panel">\n      <h2>Sonuç</h2>\n      <p>Daha doğru lokasyon bazlı kayıtlar, daha güçlü devam görünürlüğü ve daha düzenli saha operasyonları elde edildi. Sonuç, lojistik ekiplerinde daha güvenilir iş gücü verisi ve daha kontrollü operasyon oldu.</p>\n    </div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:16px;">\n  <div class="case-shell">\n    <div class="section-head narrow" style="margin-bottom:22px;">\n      <p class="eyebrow">FAQ</p>\n      <h2>Sık Sorulan Sorular</h2>\n    </div>\n    <div class="faq-wrap"><div class="faq-card"><h3>Geofencing devam software lojistikte nasıl kullanılır?</h3><p>Saha ekiplerinin doğru noktadan check-in/check-out yapmasını destekleyerek devam doğruluğunu artırır.</p></div><div class="faq-card"><h3>QR check-in ve GPS doğrulama hangi avantajları sağlar?</h3><p>Lokasyon doğruluğu, operasyonel güven ve merkezi iş gücü görünürlüğü sağlar.</p></div><div class="faq-card"><h3>Saha ekiplerinde devam tracking neden zorlaşır?</h3><p>Dağıtık ekip yapısı, farklı lokasyonlar ve yüksek hareketlilik nedeniyle takip daha karmaşık hale gelir.</p></div></div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:20px;">\n  <div class="case-shell">\n    <div class="section-head narrow" style="margin-bottom:22px;">\n      <p class="eyebrow">CADRO HRMS</p>\n      <h2>İlgili sayfalar</h2>\n    </div>\n    <div class="related-grid"><a class="related-card" href="puantaj-ve-vardiya-yazilimi.html"><strong>devam yazılımını incele</strong><span>Zaman, vardiya ve devam akışlarını tek yapıda yönetin.</span></a><a class="related-card" href="security.html"><strong>Güvenlik yaklaşımını incele</strong><span>Rol bazlı erişim ve kayıt görünürlüğünü destekleyen güvenlik katmanlarını keşfedin.</span></a><a class="related-card" href="ik-yazilimi.html"><strong>İKYS yaklaşımını incele</strong><span>Bulut tabanlı İK yazılımı platformunun saha ekiplerine nasıl uyum sağladığını görün.</span></a></div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:18px;">\n  <div class="case-shell">\n    <div class="cta-panel">\n      <h2>Saha ekiplerinde daha güvenilir devam görünürlüğü</h2>\n      <p>CADRO İKYS; devam, çalışan verisi ve operasyonel görünürlüğü tek bulut platformunda birleştirir.</p>\n      <a class="primary-button" href="ik-yazilimi.html">CADRO HRMS</a>\n    </div>\n  </div>\n</section>\n\n`,"vaka-calismasi-uretim-devi":`\n<section class="case-hero">\n  <div class="case-shell">\n    <div class="case-breadcrumbs"><span>Ana Sayfa / Vaka Çalışmaları / Üretim</span></div>\n    <div class="case-hero-grid">\n      <div>\n        <div class="industry">ÜRETİM</div>\n        <h1>Büyük Ölçekli Üretim Operasyonlarında İKYS ile Süreçleri Entegre Yönetmek</h1>\n        <p>Büyük organizasyonlarda farklı İK süreçlerini tek bir yapıda yönetmek, operasyonel netlik açısından kritik önemdedir. Bu vaka çalışması, CADRO İKYS ile çalışan yönetimi, vardiya, izin, masraf ve iç taleplerin daha entegre hale gelmesini ele alır.</p>\n      </div>\n      <div class="case-shot"><img src="./assets/screenshots/phase4/tr/expenses.webp" alt="CADRO ÜRETİM İK yazılımı ekran görüntüsü" loading="eager"/></div>\n    </div>\n  </div>\n</section>\n<section class="section-pad">\n  <div class="case-shell two-col">\n    <div class="section-box">\n      <h2>Zorluk</h2>\n      <ul><li>Çalışan verisi, vardiya, izin, masraf ve iç talepler farklı noktalarda yönetiliyordu.</li><li>Bu parçalı yapı süreç görünürlüğünü azaltıyor ve manuel koordinasyon yükünü artırıyordu.</li><li>Operasyon büyüdükçe yönetsel görünürlük ile süreç standardizasyonu aynı hızda gelişmiyordu.</li></ul>\n    </div>\n    <div class="section-box">\n      <h2>CADRO yaklaşımı</h2>\n      <ul><li>çalışan yönetimi, izin yönetimi, devam takibi ve finansal operasyon akışları tek İKYS altında toplandı.</li><li>Farklı ekiplerin aynı operasyonel dilde çalışabileceği daha merkezi bir model kuruldu.</li><li>İK ve operasyon verisi daha görünür hale gelerek yönetim ekiplerine daha güçlü kontrol alanı sağlandı.</li></ul>\n    </div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:0;">\n  <div class="case-shell">\n    <div class="result-panel">\n      <h2>Sonuç</h2>\n      <p>Daha güçlü süreç standardizasyonu, daha net iç akışlar ve daha yüksek yönetsel görünürlük sağlandı. Sonuç olarak İK operasyonları yalnızca daha hızlı değil, aynı zamanda daha kurumsal ve daha sürdürülebilir hale geldi.</p>\n    </div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:16px;">\n  <div class="case-shell">\n    <div class="section-head narrow" style="margin-bottom:22px;">\n      <p class="eyebrow">FAQ</p>\n      <h2>Sık Sorulan Sorular</h2>\n    </div>\n    <div class="faq-wrap"><div class="faq-card"><h3>Büyük üretim şirketleri için İKYS neden gereklidir?</h3><p>Çünkü çok katmanlı iş gücü operasyonlarında çalışan verisi, vardiya, izin ve iç taleplerin tek sistemde görünür olması gerekir.</p></div><div class="faq-card"><h3>çalışan yönetimi, leave ve shift planning neden tek sistemde olmalı?</h3><p>Çünkü ayrı sistemler görünürlük kaybına ve daha fazla manuel koordinasyona yol açar.</p></div><div class="faq-card"><h3>bulut tabanlı İK yazılımı büyük operasyonlarda nasıl ölçeklenir?</h3><p>Yetkilendirme, modüler yapı ve merkezi veri yönetimi ile büyüyen organizasyonlara uyum sağlar.</p></div></div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:20px;">\n  <div class="case-shell">\n    <div class="section-head narrow" style="margin-bottom:22px;">\n      <p class="eyebrow">CADRO HRMS</p>\n      <h2>İlgili sayfalar</h2>\n    </div>\n    <div class="related-grid"><a class="related-card" href="ik-yazilimi.html"><strong>İKYS yaklaşımını incele</strong><span>CADRO’nun bulut tabanlı İK yazılımı yapısının büyük organizasyonlara nasıl uyduğunu görün.</span></a><a class="related-card" href="puantaj-ve-vardiya-yazilimi.html"><strong>Vardiya ve devam yapısını incele</strong><span>Çalışma planları ve devam süreçlerini bordroya hazır yönetin.</span></a><a class="related-card" href="masraf-ve-satin-alma.html"><strong>Masraf ve satın alma akışlarını incele</strong><span>İç talepleri ve finansal operasyonları daha görünür yönetin.</span></a></div>\n  </div>\n</section>\n<section class="section-pad" style="padding-top:18px;">\n  <div class="case-shell">\n    <div class="cta-panel">\n      <h2>Büyük iş gücü operasyonlarını tek İKYS yapısında yönetin</h2>\n      <p>CADRO İKYS ile çalışan verisi, vardiya, izin ve operasyonel akışları bulut tabanlı tek bir platformda birleştirin.</p>\n      <a class="primary-button" href="ik-yazilimi.html">CADRO HRMS</a>\n    </div>\n  </div>\n</section>\n\n`};